((SELECT id FROM mst_surah WHERE surah_number = 50), 33, 'مَّنْ خَشِىَ ٱلرَّحْمَٰنَ بِٱلْغَيْبِ وَجَآءَ بِقَلْبٍۢ مُّنِيبٍ', NULL, 26, 208, 7, 519, false, NOW(), NOW()),
