((SELECT id FROM mst_surah WHERE surah_number = 50), 35, 'لَهُم مَّا يَشَآءُونَ فِيهَا وَلَدَيْنَا مَزِيدٌۭ', NULL, 26, 208, 7, 519, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 50), 36, 'وَكَمْ أَهْلَكْنَا قَبْلَهُم مِّن قَرْنٍ هُمْ أَشَدُّ مِنْهُم بَطْشًۭا فَنَقَّبُوا۟ فِى ٱلْبِلَٰدِ هَلْ مِن مَّحِيصٍ', NULL, 26, 208, 7, 520, false, NOW(), NOW()),
