((SELECT id FROM mst_surah WHERE surah_number = 50), 39, 'فَٱصْبِرْ عَلَىٰ مَا يَقُولُونَ وَسَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ ٱلشَّمْسِ وَقَبْلَ ٱلْغُرُوبِ', NULL, 26, 208, 7, 520, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 50), 40, 'وَمِنَ ٱلَّيْلِ فَسَبِّحْهُ وَأَدْبَٰرَ ٱلسُّجُودِ', NULL, 26, 208, 7, 520, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 50), 41, 'وَٱسْتَمِعْ يَوْمَ يُنَادِ ٱلْمُنَادِ مِن مَّكَانٍۢ قَرِيبٍۢ', NULL, 26, 208, 7, 520, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 50), 42, 'يَوْمَ يَسْمَعُونَ ٱلصَّيْحَةَ بِٱلْحَقِّ ۚ ذَٰلِكَ يَوْمُ ٱلْخُرُوجِ', NULL, 26, 208, 7, 520, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 50), 43, 'إِنَّا نَحْنُ نُحْىِۦ وَنُمِيتُ وَإِلَيْنَا ٱلْمَصِيرُ', NULL, 26, 208, 7, 520, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 50), 44, 'يَوْمَ تَشَقَّقُ ٱلْأَرْضُ عَنْهُمْ سِرَاعًۭا ۚ ذَٰلِكَ حَشْرٌ عَلَيْنَا يَسِيرٌۭ', NULL, 26, 208, 7, 520, false, NOW(), NOW()),
