((SELECT id FROM mst_surah WHERE surah_number = 51), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ وَٱلذَّٰرِيَٰتِ ذَرْوًۭا', NULL, 26, 208, 7, 520, false, NOW(), NOW()),
