((SELECT id FROM mst_surah WHERE surah_number = 51), 17, 'كَانُوا۟ قَلِيلًۭا مِّنَ ٱلَّيْلِ مَا يَهْجَعُونَ', NULL, 26, 208, 7, 521, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 51), 18, 'وَبِٱلْأَسْحَارِ هُمْ يَسْتَغْفِرُونَ', NULL, 26, 208, 7, 521, false, NOW(), NOW()),
