((SELECT id FROM mst_surah WHERE surah_number = 51), 20, 'وَفِى ٱلْأَرْضِ ءَايَٰتٌۭ لِّلْمُوقِنِينَ', NULL, 26, 208, 7, 521, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 51), 21, 'وَفِىٓ أَنفُسِكُمْ ۚ أَفَلَا تُبْصِرُونَ', NULL, 26, 208, 7, 521, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 51), 22, 'وَفِى ٱلسَّمَآءِ رِزْقُكُمْ وَمَا تُوعَدُونَ', NULL, 26, 208, 7, 521, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 51), 23, 'فَوَرَبِّ ٱلسَّمَآءِ وَٱلْأَرْضِ إِنَّهُۥ لَحَقٌّۭ مِّثْلَ مَآ أَنَّكُمْ تَنطِقُونَ', NULL, 26, 208, 7, 521, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 51), 24, 'هَلْ أَتَىٰكَ حَدِيثُ ضَيْفِ إِبْرَٰهِيمَ ٱلْمُكْرَمِينَ', NULL, 26, 208, 7, 521, false, NOW(), NOW()),
