((SELECT id FROM mst_surah WHERE surah_number = 51), 31, '۞ قَالَ فَمَا خَطْبُكُمْ أَيُّهَا ٱلْمُرْسَلُونَ', NULL, 27, 209, 7, 522, false, NOW(), NOW()),
