((SELECT id FROM mst_surah WHERE surah_number = 51), 36, 'فَمَا وَجَدْنَا فِيهَا غَيْرَ بَيْتٍۢ مِّنَ ٱلْمُسْلِمِينَ', NULL, 27, 209, 7, 522, false, NOW(), NOW()),
