((SELECT id FROM mst_surah WHERE surah_number = 51), 38, 'وَفِى مُوسَىٰٓ إِذْ أَرْسَلْنَٰهُ إِلَىٰ فِرْعَوْنَ بِسُلْطَٰنٍۢ مُّبِينٍۢ', NULL, 27, 209, 7, 522, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 51), 39, 'فَتَوَلَّىٰ بِرُكْنِهِۦ وَقَالَ سَٰحِرٌ أَوْ مَجْنُونٌۭ', NULL, 27, 209, 7, 522, false, NOW(), NOW()),
