((SELECT id FROM mst_surah WHERE surah_number = 51), 43, 'وَفِى ثَمُودَ إِذْ قِيلَ لَهُمْ تَمَتَّعُوا۟ حَتَّىٰ حِينٍۢ', NULL, 27, 209, 7, 522, false, NOW(), NOW()),
