((SELECT id FROM mst_surah WHERE surah_number = 56), 70, 'لَوْ نَشَآءُ جَعَلْنَٰهُ أُجَاجًۭا فَلَوْلَا تَشْكُرُونَ', NULL, 27, 214, 7, 536, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 71, 'أَفَرَءَيْتُمُ ٱلنَّارَ ٱلَّتِى تُورُونَ', NULL, 27, 214, 7, 536, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 72, 'ءَأَنتُمْ أَنشَأْتُمْ شَجَرَتَهَآ أَمْ نَحْنُ ٱلْمُنشِـُٔونَ', NULL, 27, 214, 7, 536, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 73, 'نَحْنُ جَعَلْنَٰهَا تَذْكِرَةًۭ وَمَتَٰعًۭا لِّلْمُقْوِينَ', NULL, 27, 214, 7, 536, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 74, 'فَسَبِّحْ بِٱسْمِ رَبِّكَ ٱلْعَظِيمِ', NULL, 27, 214, 7, 536, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 75, '۞ فَلَآ أُقْسِمُ بِمَوَٰقِعِ ٱلنُّجُومِ', NULL, 27, 215, 7, 536, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 76, 'وَإِنَّهُۥ لَقَسَمٌۭ لَّوْ تَعْلَمُونَ عَظِيمٌ', NULL, 27, 215, 7, 536, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 77, 'إِنَّهُۥ لَقُرْءَانٌۭ كَرِيمٌۭ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 78, 'فِى كِتَٰبٍۢ مَّكْنُونٍۢ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 79, 'لَّا يَمَسُّهُۥٓ إِلَّا ٱلْمُطَهَّرُونَ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 80, 'تَنزِيلٌۭ مِّن رَّبِّ ٱلْعَٰلَمِينَ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 81, 'أَفَبِهَٰذَا ٱلْحَدِيثِ أَنتُم مُّدْهِنُونَ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 82, 'وَتَجْعَلُونَ رِزْقَكُمْ أَنَّكُمْ تُكَذِّبُونَ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 83, 'فَلَوْلَآ إِذَا بَلَغَتِ ٱلْحُلْقُومَ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 84, 'وَأَنتُمْ حِينَئِذٍۢ تَنظُرُونَ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 85, 'وَنَحْنُ أَقْرَبُ إِلَيْهِ مِنكُمْ وَلَٰكِن لَّا تُبْصِرُونَ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 86, 'فَلَوْلَآ إِن كُنتُمْ غَيْرَ مَدِينِينَ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 87, 'تَرْجِعُونَهَآ إِن كُنتُمْ صَٰدِقِينَ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 88, 'فَأَمَّآ إِن كَانَ مِنَ ٱلْمُقَرَّبِينَ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 89, 'فَرَوْحٌۭ وَرَيْحَانٌۭ وَجَنَّتُ نَعِيمٍۢ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 90, 'وَأَمَّآ إِن كَانَ مِنْ أَصْحَٰبِ ٱلْيَمِينِ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 91, 'فَسَلَٰمٌۭ لَّكَ مِنْ أَصْحَٰبِ ٱلْيَمِينِ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 92, 'وَأَمَّآ إِن كَانَ مِنَ ٱلْمُكَذِّبِينَ ٱلضَّآلِّينَ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 93, 'فَنُزُلٌۭ مِّنْ حَمِيمٍۢ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 94, 'وَتَصْلِيَةُ جَحِيمٍ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 95, 'إِنَّ هَٰذَا لَهُوَ حَقُّ ٱلْيَقِينِ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 56), 96, 'فَسَبِّحْ بِٱسْمِ رَبِّكَ ٱلْعَظِيمِ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ سَبَّحَ لِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 2, 'لَهُۥ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ يُحْىِۦ وَيُمِيتُ ۖ وَهُوَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 3, 'هُوَ ٱلْأَوَّلُ وَٱلْءَاخِرُ وَٱلظَّٰهِرُ وَٱلْبَاطِنُ ۖ وَهُوَ بِكُلِّ شَىْءٍ عَلِيمٌ', NULL, 27, 215, 7, 537, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 4, 'هُوَ ٱلَّذِى خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ فِى سِتَّةِ أَيَّامٍۢ ثُمَّ ٱسْتَوَىٰ عَلَى ٱلْعَرْشِ ۚ يَعْلَمُ مَا يَلِجُ فِى ٱلْأَرْضِ وَمَا يَخْرُجُ مِنْهَا وَمَا يَنزِلُ مِنَ ٱلسَّمَآءِ وَمَا يَعْرُجُ فِيهَا ۖ وَهُوَ مَعَكُمْ أَيْنَ مَا كُنتُمْ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌۭ', NULL, 27, 215, 7, 538, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 5, 'لَّهُۥ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ وَإِلَى ٱللَّهِ تُرْجَعُ ٱلْأُمُورُ', NULL, 27, 215, 7, 538, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 6, 'يُولِجُ ٱلَّيْلَ فِى ٱلنَّهَارِ وَيُولِجُ ٱلنَّهَارَ فِى ٱلَّيْلِ ۚ وَهُوَ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ', NULL, 27, 215, 7, 538, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 7, 'ءَامِنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ وَأَنفِقُوا۟ مِمَّا جَعَلَكُم مُّسْتَخْلَفِينَ فِيهِ ۖ فَٱلَّذِينَ ءَامَنُوا۟ مِنكُمْ وَأَنفَقُوا۟ لَهُمْ أَجْرٌۭ كَبِيرٌۭ', NULL, 27, 215, 7, 538, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 8, 'وَمَا لَكُمْ لَا تُؤْمِنُونَ بِٱللَّهِ ۙ وَٱلرَّسُولُ يَدْعُوكُمْ لِتُؤْمِنُوا۟ بِرَبِّكُمْ وَقَدْ أَخَذَ مِيثَٰقَكُمْ إِن كُنتُم مُّؤْمِنِينَ', NULL, 27, 215, 7, 538, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 9, 'هُوَ ٱلَّذِى يُنَزِّلُ عَلَىٰ عَبْدِهِۦٓ ءَايَٰتٍۭ بَيِّنَٰتٍۢ لِّيُخْرِجَكُم مِّنَ ٱلظُّلُمَٰتِ إِلَى ٱلنُّورِ ۚ وَإِنَّ ٱللَّهَ بِكُمْ لَرَءُوفٌۭ رَّحِيمٌۭ', NULL, 27, 215, 7, 538, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 10, 'وَمَا لَكُمْ أَلَّا تُنفِقُوا۟ فِى سَبِيلِ ٱللَّهِ وَلِلَّهِ مِيرَٰثُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ لَا يَسْتَوِى مِنكُم مَّنْ أَنفَقَ مِن قَبْلِ ٱلْفَتْحِ وَقَٰتَلَ ۚ أُو۟لَٰٓئِكَ أَعْظَمُ دَرَجَةًۭ مِّنَ ٱلَّذِينَ أَنفَقُوا۟ مِنۢ بَعْدُ وَقَٰتَلُوا۟ ۚ وَكُلًّۭا وَعَدَ ٱللَّهُ ٱلْحُسْنَىٰ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌۭ', NULL, 27, 215, 7, 538, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 11, 'مَّن ذَا ٱلَّذِى يُقْرِضُ ٱللَّهَ قَرْضًا حَسَنًۭا فَيُضَٰعِفَهُۥ لَهُۥ وَلَهُۥٓ أَجْرٌۭ كَرِيمٌۭ', NULL, 27, 215, 7, 538, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 12, 'يَوْمَ تَرَى ٱلْمُؤْمِنِينَ وَٱلْمُؤْمِنَٰتِ يَسْعَىٰ نُورُهُم بَيْنَ أَيْدِيهِمْ وَبِأَيْمَٰنِهِم بُشْرَىٰكُمُ ٱلْيَوْمَ جَنَّٰتٌۭ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا ۚ ذَٰلِكَ هُوَ ٱلْفَوْزُ ٱلْعَظِيمُ', NULL, 27, 215, 7, 539, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 13, 'يَوْمَ يَقُولُ ٱلْمُنَٰفِقُونَ وَٱلْمُنَٰفِقَٰتُ لِلَّذِينَ ءَامَنُوا۟ ٱنظُرُونَا نَقْتَبِسْ مِن نُّورِكُمْ قِيلَ ٱرْجِعُوا۟ وَرَآءَكُمْ فَٱلْتَمِسُوا۟ نُورًۭا فَضُرِبَ بَيْنَهُم بِسُورٍۢ لَّهُۥ بَابٌۢ بَاطِنُهُۥ فِيهِ ٱلرَّحْمَةُ وَظَٰهِرُهُۥ مِن قِبَلِهِ ٱلْعَذَابُ', NULL, 27, 215, 7, 539, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 14, 'يُنَادُونَهُمْ أَلَمْ نَكُن مَّعَكُمْ ۖ قَالُوا۟ بَلَىٰ وَلَٰكِنَّكُمْ فَتَنتُمْ أَنفُسَكُمْ وَتَرَبَّصْتُمْ وَٱرْتَبْتُمْ وَغَرَّتْكُمُ ٱلْأَمَانِىُّ حَتَّىٰ جَآءَ أَمْرُ ٱللَّهِ وَغَرَّكُم بِٱللَّهِ ٱلْغَرُورُ', NULL, 27, 215, 7, 539, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 15, 'فَٱلْيَوْمَ لَا يُؤْخَذُ مِنكُمْ فِدْيَةٌۭ وَلَا مِنَ ٱلَّذِينَ كَفَرُوا۟ ۚ مَأْوَىٰكُمُ ٱلنَّارُ ۖ هِىَ مَوْلَىٰكُمْ ۖ وَبِئْسَ ٱلْمَصِيرُ', NULL, 27, 215, 7, 539, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 16, '۞ أَلَمْ يَأْنِ لِلَّذِينَ ءَامَنُوٓا۟ أَن تَخْشَعَ قُلُوبُهُمْ لِذِكْرِ ٱللَّهِ وَمَا نَزَلَ مِنَ ٱلْحَقِّ وَلَا يَكُونُوا۟ كَٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ مِن قَبْلُ فَطَالَ عَلَيْهِمُ ٱلْأَمَدُ فَقَسَتْ قُلُوبُهُمْ ۖ وَكَثِيرٌۭ مِّنْهُمْ فَٰسِقُونَ', NULL, 27, 216, 7, 539, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 17, 'ٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ يُحْىِ ٱلْأَرْضَ بَعْدَ مَوْتِهَا ۚ قَدْ بَيَّنَّا لَكُمُ ٱلْءَايَٰتِ لَعَلَّكُمْ تَعْقِلُونَ', NULL, 27, 216, 7, 539, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 18, 'إِنَّ ٱلْمُصَّدِّقِينَ وَٱلْمُصَّدِّقَٰتِ وَأَقْرَضُوا۟ ٱللَّهَ قَرْضًا حَسَنًۭا يُضَٰعَفُ لَهُمْ وَلَهُمْ أَجْرٌۭ كَرِيمٌۭ', NULL, 27, 216, 7, 539, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 19, 'وَٱلَّذِينَ ءَامَنُوا۟ بِٱللَّهِ وَرُسُلِهِۦٓ أُو۟لَٰٓئِكَ هُمُ ٱلصِّدِّيقُونَ ۖ وَٱلشُّهَدَآءُ عِندَ رَبِّهِمْ لَهُمْ أَجْرُهُمْ وَنُورُهُمْ ۖ وَٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَٰتِنَآ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلْجَحِيمِ', NULL, 27, 216, 7, 540, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 20, 'ٱعْلَمُوٓا۟ أَنَّمَا ٱلْحَيَوٰةُ ٱلدُّنْيَا لَعِبٌۭ وَلَهْوٌۭ وَزِينَةٌۭ وَتَفَاخُرٌۢ بَيْنَكُمْ وَتَكَاثُرٌۭ فِى ٱلْأَمْوَٰلِ وَٱلْأَوْلَٰدِ ۖ كَمَثَلِ غَيْثٍ أَعْجَبَ ٱلْكُفَّارَ نَبَاتُهُۥ ثُمَّ يَهِيجُ فَتَرَىٰهُ مُصْفَرًّۭا ثُمَّ يَكُونُ حُطَٰمًۭا ۖ وَفِى ٱلْءَاخِرَةِ عَذَابٌۭ شَدِيدٌۭ وَمَغْفِرَةٌۭ مِّنَ ٱللَّهِ وَرِضْوَٰنٌۭ ۚ وَمَا ٱلْحَيَوٰةُ ٱلدُّنْيَآ إِلَّا مَتَٰعُ ٱلْغُرُورِ', NULL, 27, 216, 7, 540, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 21, 'سَابِقُوٓا۟ إِلَىٰ مَغْفِرَةٍۢ مِّن رَّبِّكُمْ وَجَنَّةٍ عَرْضُهَا كَعَرْضِ ٱلسَّمَآءِ وَٱلْأَرْضِ أُعِدَّتْ لِلَّذِينَ ءَامَنُوا۟ بِٱللَّهِ وَرُسُلِهِۦ ۚ ذَٰلِكَ فَضْلُ ٱللَّهِ يُؤْتِيهِ مَن يَشَآءُ ۚ وَٱللَّهُ ذُو ٱلْفَضْلِ ٱلْعَظِيمِ', NULL, 27, 216, 7, 540, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 22, 'مَآ أَصَابَ مِن مُّصِيبَةٍۢ فِى ٱلْأَرْضِ وَلَا فِىٓ أَنفُسِكُمْ إِلَّا فِى كِتَٰبٍۢ مِّن قَبْلِ أَن نَّبْرَأَهَآ ۚ إِنَّ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٌۭ', NULL, 27, 216, 7, 540, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 23, 'لِّكَيْلَا تَأْسَوْا۟ عَلَىٰ مَا فَاتَكُمْ وَلَا تَفْرَحُوا۟ بِمَآ ءَاتَىٰكُمْ ۗ وَٱللَّهُ لَا يُحِبُّ كُلَّ مُخْتَالٍۢ فَخُورٍ', NULL, 27, 216, 7, 540, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 24, 'ٱلَّذِينَ يَبْخَلُونَ وَيَأْمُرُونَ ٱلنَّاسَ بِٱلْبُخْلِ ۗ وَمَن يَتَوَلَّ فَإِنَّ ٱللَّهَ هُوَ ٱلْغَنِىُّ ٱلْحَمِيدُ', NULL, 27, 216, 7, 540, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 25, 'لَقَدْ أَرْسَلْنَا رُسُلَنَا بِٱلْبَيِّنَٰتِ وَأَنزَلْنَا مَعَهُمُ ٱلْكِتَٰبَ وَٱلْمِيزَانَ لِيَقُومَ ٱلنَّاسُ بِٱلْقِسْطِ ۖ وَأَنزَلْنَا ٱلْحَدِيدَ فِيهِ بَأْسٌۭ شَدِيدٌۭ وَمَنَٰفِعُ لِلنَّاسِ وَلِيَعْلَمَ ٱللَّهُ مَن يَنصُرُهُۥ وَرُسُلَهُۥ بِٱلْغَيْبِ ۚ إِنَّ ٱللَّهَ قَوِىٌّ عَزِيزٌۭ', NULL, 27, 216, 7, 541, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 26, 'وَلَقَدْ أَرْسَلْنَا نُوحًۭا وَإِبْرَٰهِيمَ وَجَعَلْنَا فِى ذُرِّيَّتِهِمَا ٱلنُّبُوَّةَ وَٱلْكِتَٰبَ ۖ فَمِنْهُم مُّهْتَدٍۢ ۖ وَكَثِيرٌۭ مِّنْهُمْ فَٰسِقُونَ', NULL, 27, 216, 7, 541, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 27, 'ثُمَّ قَفَّيْنَا عَلَىٰٓ ءَاثَٰرِهِم بِرُسُلِنَا وَقَفَّيْنَا بِعِيسَى ٱبْنِ مَرْيَمَ وَءَاتَيْنَٰهُ ٱلْإِنجِيلَ وَجَعَلْنَا فِى قُلُوبِ ٱلَّذِينَ ٱتَّبَعُوهُ رَأْفَةًۭ وَرَحْمَةًۭ وَرَهْبَانِيَّةً ٱبْتَدَعُوهَا مَا كَتَبْنَٰهَا عَلَيْهِمْ إِلَّا ٱبْتِغَآءَ رِضْوَٰنِ ٱللَّهِ فَمَا رَعَوْهَا حَقَّ رِعَايَتِهَا ۖ فَـَٔاتَيْنَا ٱلَّذِينَ ءَامَنُوا۟ مِنْهُمْ أَجْرَهُمْ ۖ وَكَثِيرٌۭ مِّنْهُمْ فَٰسِقُونَ', NULL, 27, 216, 7, 541, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 28, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ وَءَامِنُوا۟ بِرَسُولِهِۦ يُؤْتِكُمْ كِفْلَيْنِ مِن رَّحْمَتِهِۦ وَيَجْعَل لَّكُمْ نُورًۭا تَمْشُونَ بِهِۦ وَيَغْفِرْ لَكُمْ ۚ وَٱللَّهُ غَفُورٌۭ رَّحِيمٌۭ', NULL, 27, 216, 7, 541, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 57), 29, 'لِّئَلَّا يَعْلَمَ أَهْلُ ٱلْكِتَٰبِ أَلَّا يَقْدِرُونَ عَلَىٰ شَىْءٍۢ مِّن فَضْلِ ٱللَّهِ ۙ وَأَنَّ ٱلْفَضْلَ بِيَدِ ٱللَّهِ يُؤْتِيهِ مَن يَشَآءُ ۚ وَٱللَّهُ ذُو ٱلْفَضْلِ ٱلْعَظِيمِ', NULL, 27, 216, 7, 541, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ قَدْ سَمِعَ ٱللَّهُ قَوْلَ ٱلَّتِى تُجَٰدِلُكَ فِى زَوْجِهَا وَتَشْتَكِىٓ إِلَى ٱللَّهِ وَٱللَّهُ يَسْمَعُ تَحَاوُرَكُمَآ ۚ إِنَّ ٱللَّهَ سَمِيعٌۢ بَصِيرٌ', NULL, 28, 217, 7, 542, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 2, 'ٱلَّذِينَ يُظَٰهِرُونَ مِنكُم مِّن نِّسَآئِهِم مَّا هُنَّ أُمَّهَٰتِهِمْ ۖ إِنْ أُمَّهَٰتُهُمْ إِلَّا ٱلَّٰٓـِٔى وَلَدْنَهُمْ ۚ وَإِنَّهُمْ لَيَقُولُونَ مُنكَرًۭا مِّنَ ٱلْقَوْلِ وَزُورًۭا ۚ وَإِنَّ ٱللَّهَ لَعَفُوٌّ غَفُورٌۭ', NULL, 28, 217, 7, 542, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 3, 'وَٱلَّذِينَ يُظَٰهِرُونَ مِن نِّسَآئِهِمْ ثُمَّ يَعُودُونَ لِمَا قَالُوا۟ فَتَحْرِيرُ رَقَبَةٍۢ مِّن قَبْلِ أَن يَتَمَآسَّا ۚ ذَٰلِكُمْ تُوعَظُونَ بِهِۦ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌۭ', NULL, 28, 217, 7, 542, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 4, 'فَمَن لَّمْ يَجِدْ فَصِيَامُ شَهْرَيْنِ مُتَتَابِعَيْنِ مِن قَبْلِ أَن يَتَمَآسَّا ۖ فَمَن لَّمْ يَسْتَطِعْ فَإِطْعَامُ سِتِّينَ مِسْكِينًۭا ۚ ذَٰلِكَ لِتُؤْمِنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ ۚ وَتِلْكَ حُدُودُ ٱللَّهِ ۗ وَلِلْكَٰفِرِينَ عَذَابٌ أَلِيمٌ', NULL, 28, 217, 7, 542, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 5, 'إِنَّ ٱلَّذِينَ يُحَآدُّونَ ٱللَّهَ وَرَسُولَهُۥ كُبِتُوا۟ كَمَا كُبِتَ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ وَقَدْ أَنزَلْنَآ ءَايَٰتٍۭ بَيِّنَٰتٍۢ ۚ وَلِلْكَٰفِرِينَ عَذَابٌۭ مُّهِينٌۭ', NULL, 28, 217, 7, 542, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 6, 'يَوْمَ يَبْعَثُهُمُ ٱللَّهُ جَمِيعًۭا فَيُنَبِّئُهُم بِمَا عَمِلُوٓا۟ ۚ أَحْصَىٰهُ ٱللَّهُ وَنَسُوهُ ۚ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍۢ شَهِيدٌ', NULL, 28, 217, 7, 542, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 7, 'أَلَمْ تَرَ أَنَّ ٱللَّهَ يَعْلَمُ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۖ مَا يَكُونُ مِن نَّجْوَىٰ ثَلَٰثَةٍ إِلَّا هُوَ رَابِعُهُمْ وَلَا خَمْسَةٍ إِلَّا هُوَ سَادِسُهُمْ وَلَآ أَدْنَىٰ مِن ذَٰلِكَ وَلَآ أَكْثَرَ إِلَّا هُوَ مَعَهُمْ أَيْنَ مَا كَانُوا۟ ۖ ثُمَّ يُنَبِّئُهُم بِمَا عَمِلُوا۟ يَوْمَ ٱلْقِيَٰمَةِ ۚ إِنَّ ٱللَّهَ بِكُلِّ شَىْءٍ عَلِيمٌ', NULL, 28, 217, 7, 543, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 8, 'أَلَمْ تَرَ إِلَى ٱلَّذِينَ نُهُوا۟ عَنِ ٱلنَّجْوَىٰ ثُمَّ يَعُودُونَ لِمَا نُهُوا۟ عَنْهُ وَيَتَنَٰجَوْنَ بِٱلْإِثْمِ وَٱلْعُدْوَٰنِ وَمَعْصِيَتِ ٱلرَّسُولِ وَإِذَا جَآءُوكَ حَيَّوْكَ بِمَا لَمْ يُحَيِّكَ بِهِ ٱللَّهُ وَيَقُولُونَ فِىٓ أَنفُسِهِمْ لَوْلَا يُعَذِّبُنَا ٱللَّهُ بِمَا نَقُولُ ۚ حَسْبُهُمْ جَهَنَّمُ يَصْلَوْنَهَا ۖ فَبِئْسَ ٱلْمَصِيرُ', NULL, 28, 217, 7, 543, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 9, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا تَنَٰجَيْتُمْ فَلَا تَتَنَٰجَوْا۟ بِٱلْإِثْمِ وَٱلْعُدْوَٰنِ وَمَعْصِيَتِ ٱلرَّسُولِ وَتَنَٰجَوْا۟ بِٱلْبِرِّ وَٱلتَّقْوَىٰ ۖ وَٱتَّقُوا۟ ٱللَّهَ ٱلَّذِىٓ إِلَيْهِ تُحْشَرُونَ', NULL, 28, 217, 7, 543, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 10, 'إِنَّمَا ٱلنَّجْوَىٰ مِنَ ٱلشَّيْطَٰنِ لِيَحْزُنَ ٱلَّذِينَ ءَامَنُوا۟ وَلَيْسَ بِضَآرِّهِمْ شَيْـًٔا إِلَّا بِإِذْنِ ٱللَّهِ ۚ وَعَلَى ٱللَّهِ فَلْيَتَوَكَّلِ ٱلْمُؤْمِنُونَ', NULL, 28, 217, 7, 543, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 11, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا قِيلَ لَكُمْ تَفَسَّحُوا۟ فِى ٱلْمَجَٰلِسِ فَٱفْسَحُوا۟ يَفْسَحِ ٱللَّهُ لَكُمْ ۖ وَإِذَا قِيلَ ٱنشُزُوا۟ فَٱنشُزُوا۟ يَرْفَعِ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ مِنكُمْ وَٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ دَرَجَٰتٍۢ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌۭ', NULL, 28, 217, 7, 543, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 12, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا نَٰجَيْتُمُ ٱلرَّسُولَ فَقَدِّمُوا۟ بَيْنَ يَدَىْ نَجْوَىٰكُمْ صَدَقَةًۭ ۚ ذَٰلِكَ خَيْرٌۭ لَّكُمْ وَأَطْهَرُ ۚ فَإِن لَّمْ تَجِدُوا۟ فَإِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌ', NULL, 28, 217, 7, 544, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 13, 'ءَأَشْفَقْتُمْ أَن تُقَدِّمُوا۟ بَيْنَ يَدَىْ نَجْوَىٰكُمْ صَدَقَٰتٍۢ ۚ فَإِذْ لَمْ تَفْعَلُوا۟ وَتَابَ ٱللَّهُ عَلَيْكُمْ فَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ وَأَطِيعُوا۟ ٱللَّهَ وَرَسُولَهُۥ ۚ وَٱللَّهُ خَبِيرٌۢ بِمَا تَعْمَلُونَ', NULL, 28, 217, 7, 544, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 14, '۞ أَلَمْ تَرَ إِلَى ٱلَّذِينَ تَوَلَّوْا۟ قَوْمًا غَضِبَ ٱللَّهُ عَلَيْهِم مَّا هُم مِّنكُمْ وَلَا مِنْهُمْ وَيَحْلِفُونَ عَلَى ٱلْكَذِبِ وَهُمْ يَعْلَمُونَ', NULL, 28, 218, 7, 544, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 15, 'أَعَدَّ ٱللَّهُ لَهُمْ عَذَابًۭا شَدِيدًا ۖ إِنَّهُمْ سَآءَ مَا كَانُوا۟ يَعْمَلُونَ', NULL, 28, 218, 7, 544, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 16, 'ٱتَّخَذُوٓا۟ أَيْمَٰنَهُمْ جُنَّةًۭ فَصَدُّوا۟ عَن سَبِيلِ ٱللَّهِ فَلَهُمْ عَذَابٌۭ مُّهِينٌۭ', NULL, 28, 218, 7, 544, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 17, 'لَّن تُغْنِىَ عَنْهُمْ أَمْوَٰلُهُمْ وَلَآ أَوْلَٰدُهُم مِّنَ ٱللَّهِ شَيْـًٔا ۚ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَٰلِدُونَ', NULL, 28, 218, 7, 544, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 18, 'يَوْمَ يَبْعَثُهُمُ ٱللَّهُ جَمِيعًۭا فَيَحْلِفُونَ لَهُۥ كَمَا يَحْلِفُونَ لَكُمْ ۖ وَيَحْسَبُونَ أَنَّهُمْ عَلَىٰ شَىْءٍ ۚ أَلَآ إِنَّهُمْ هُمُ ٱلْكَٰذِبُونَ', NULL, 28, 218, 7, 544, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 19, 'ٱسْتَحْوَذَ عَلَيْهِمُ ٱلشَّيْطَٰنُ فَأَنسَىٰهُمْ ذِكْرَ ٱللَّهِ ۚ أُو۟لَٰٓئِكَ حِزْبُ ٱلشَّيْطَٰنِ ۚ أَلَآ إِنَّ حِزْبَ ٱلشَّيْطَٰنِ هُمُ ٱلْخَٰسِرُونَ', NULL, 28, 218, 7, 544, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 20, 'إِنَّ ٱلَّذِينَ يُحَآدُّونَ ٱللَّهَ وَرَسُولَهُۥٓ أُو۟لَٰٓئِكَ فِى ٱلْأَذَلِّينَ', NULL, 28, 218, 7, 544, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 21, 'كَتَبَ ٱللَّهُ لَأَغْلِبَنَّ أَنَا۠ وَرُسُلِىٓ ۚ إِنَّ ٱللَّهَ قَوِىٌّ عَزِيزٌۭ', NULL, 28, 218, 7, 544, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 58), 22, 'لَّا تَجِدُ قَوْمًۭا يُؤْمِنُونَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ يُوَآدُّونَ مَنْ حَآدَّ ٱللَّهَ وَرَسُولَهُۥ وَلَوْ كَانُوٓا۟ ءَابَآءَهُمْ أَوْ أَبْنَآءَهُمْ أَوْ إِخْوَٰنَهُمْ أَوْ عَشِيرَتَهُمْ ۚ أُو۟لَٰٓئِكَ كَتَبَ فِى قُلُوبِهِمُ ٱلْإِيمَٰنَ وَأَيَّدَهُم بِرُوحٍۢ مِّنْهُ ۖ وَيُدْخِلُهُمْ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا ۚ رَضِىَ ٱللَّهُ عَنْهُمْ وَرَضُوا۟ عَنْهُ ۚ أُو۟لَٰٓئِكَ حِزْبُ ٱللَّهِ ۚ أَلَآ إِنَّ حِزْبَ ٱللَّهِ هُمُ ٱلْمُفْلِحُونَ', NULL, 28, 218, 7, 545, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ سَبَّحَ لِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۖ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 28, 218, 7, 545, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 2, 'هُوَ ٱلَّذِىٓ أَخْرَجَ ٱلَّذِينَ كَفَرُوا۟ مِنْ أَهْلِ ٱلْكِتَٰبِ مِن دِيَٰرِهِمْ لِأَوَّلِ ٱلْحَشْرِ ۚ مَا ظَنَنتُمْ أَن يَخْرُجُوا۟ ۖ وَظَنُّوٓا۟ أَنَّهُم مَّانِعَتُهُمْ حُصُونُهُم مِّنَ ٱللَّهِ فَأَتَىٰهُمُ ٱللَّهُ مِنْ حَيْثُ لَمْ يَحْتَسِبُوا۟ ۖ وَقَذَفَ فِى قُلُوبِهِمُ ٱلرُّعْبَ ۚ يُخْرِبُونَ بُيُوتَهُم بِأَيْدِيهِمْ وَأَيْدِى ٱلْمُؤْمِنِينَ فَٱعْتَبِرُوا۟ يَٰٓأُو۟لِى ٱلْأَبْصَٰرِ', NULL, 28, 218, 7, 545, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 3, 'وَلَوْلَآ أَن كَتَبَ ٱللَّهُ عَلَيْهِمُ ٱلْجَلَآءَ لَعَذَّبَهُمْ فِى ٱلدُّنْيَا ۖ وَلَهُمْ فِى ٱلْءَاخِرَةِ عَذَابُ ٱلنَّارِ', NULL, 28, 218, 7, 545, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 4, 'ذَٰلِكَ بِأَنَّهُمْ شَآقُّوا۟ ٱللَّهَ وَرَسُولَهُۥ ۖ وَمَن يُشَآقِّ ٱللَّهَ فَإِنَّ ٱللَّهَ شَدِيدُ ٱلْعِقَابِ', NULL, 28, 218, 7, 546, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 5, 'مَا قَطَعْتُم مِّن لِّينَةٍ أَوْ تَرَكْتُمُوهَا قَآئِمَةً عَلَىٰٓ أُصُولِهَا فَبِإِذْنِ ٱللَّهِ وَلِيُخْزِىَ ٱلْفَٰسِقِينَ', NULL, 28, 218, 7, 546, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 6, 'وَمَآ أَفَآءَ ٱللَّهُ عَلَىٰ رَسُولِهِۦ مِنْهُمْ فَمَآ أَوْجَفْتُمْ عَلَيْهِ مِنْ خَيْلٍۢ وَلَا رِكَابٍۢ وَلَٰكِنَّ ٱللَّهَ يُسَلِّطُ رُسُلَهُۥ عَلَىٰ مَن يَشَآءُ ۚ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ', NULL, 28, 218, 7, 546, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 7, 'مَّآ أَفَآءَ ٱللَّهُ عَلَىٰ رَسُولِهِۦ مِنْ أَهْلِ ٱلْقُرَىٰ فَلِلَّهِ وَلِلرَّسُولِ وَلِذِى ٱلْقُرْبَىٰ وَٱلْيَتَٰمَىٰ وَٱلْمَسَٰكِينِ وَٱبْنِ ٱلسَّبِيلِ كَىْ لَا يَكُونَ دُولَةًۢ بَيْنَ ٱلْأَغْنِيَآءِ مِنكُمْ ۚ وَمَآ ءَاتَىٰكُمُ ٱلرَّسُولُ فَخُذُوهُ وَمَا نَهَىٰكُمْ عَنْهُ فَٱنتَهُوا۟ ۚ وَٱتَّقُوا۟ ٱللَّهَ ۖ إِنَّ ٱللَّهَ شَدِيدُ ٱلْعِقَابِ', NULL, 28, 218, 7, 546, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 8, 'لِلْفُقَرَآءِ ٱلْمُهَٰجِرِينَ ٱلَّذِينَ أُخْرِجُوا۟ مِن دِيَٰرِهِمْ وَأَمْوَٰلِهِمْ يَبْتَغُونَ فَضْلًۭا مِّنَ ٱللَّهِ وَرِضْوَٰنًۭا وَيَنصُرُونَ ٱللَّهَ وَرَسُولَهُۥٓ ۚ أُو۟لَٰٓئِكَ هُمُ ٱلصَّٰدِقُونَ', NULL, 28, 218, 7, 546, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 9, 'وَٱلَّذِينَ تَبَوَّءُو ٱلدَّارَ وَٱلْإِيمَٰنَ مِن قَبْلِهِمْ يُحِبُّونَ مَنْ هَاجَرَ إِلَيْهِمْ وَلَا يَجِدُونَ فِى صُدُورِهِمْ حَاجَةًۭ مِّمَّآ أُوتُوا۟ وَيُؤْثِرُونَ عَلَىٰٓ أَنفُسِهِمْ وَلَوْ كَانَ بِهِمْ خَصَاصَةٌۭ ۚ وَمَن يُوقَ شُحَّ نَفْسِهِۦ فَأُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ', NULL, 28, 218, 7, 546, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 10, 'وَٱلَّذِينَ جَآءُو مِنۢ بَعْدِهِمْ يَقُولُونَ رَبَّنَا ٱغْفِرْ لَنَا وَلِإِخْوَٰنِنَا ٱلَّذِينَ سَبَقُونَا بِٱلْإِيمَٰنِ وَلَا تَجْعَلْ فِى قُلُوبِنَا غِلًّۭا لِّلَّذِينَ ءَامَنُوا۟ رَبَّنَآ إِنَّكَ رَءُوفٌۭ رَّحِيمٌ', NULL, 28, 218, 7, 547, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 11, '۞ أَلَمْ تَرَ إِلَى ٱلَّذِينَ نَافَقُوا۟ يَقُولُونَ لِإِخْوَٰنِهِمُ ٱلَّذِينَ كَفَرُوا۟ مِنْ أَهْلِ ٱلْكِتَٰبِ لَئِنْ أُخْرِجْتُمْ لَنَخْرُجَنَّ مَعَكُمْ وَلَا نُطِيعُ فِيكُمْ أَحَدًا أَبَدًۭا وَإِن قُوتِلْتُمْ لَنَنصُرَنَّكُمْ وَٱللَّهُ يَشْهَدُ إِنَّهُمْ لَكَٰذِبُونَ', NULL, 28, 219, 7, 547, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 12, 'لَئِنْ أُخْرِجُوا۟ لَا يَخْرُجُونَ مَعَهُمْ وَلَئِن قُوتِلُوا۟ لَا يَنصُرُونَهُمْ وَلَئِن نَّصَرُوهُمْ لَيُوَلُّنَّ ٱلْأَدْبَٰرَ ثُمَّ لَا يُنصَرُونَ', NULL, 28, 219, 7, 547, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 13, 'لَأَنتُمْ أَشَدُّ رَهْبَةًۭ فِى صُدُورِهِم مِّنَ ٱللَّهِ ۚ ذَٰلِكَ بِأَنَّهُمْ قَوْمٌۭ لَّا يَفْقَهُونَ', NULL, 28, 219, 7, 547, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 14, 'لَا يُقَٰتِلُونَكُمْ جَمِيعًا إِلَّا فِى قُرًۭى مُّحَصَّنَةٍ أَوْ مِن وَرَآءِ جُدُرٍۭ ۚ بَأْسُهُم بَيْنَهُمْ شَدِيدٌۭ ۚ تَحْسَبُهُمْ جَمِيعًۭا وَقُلُوبُهُمْ شَتَّىٰ ۚ ذَٰلِكَ بِأَنَّهُمْ قَوْمٌۭ لَّا يَعْقِلُونَ', NULL, 28, 219, 7, 547, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 15, 'كَمَثَلِ ٱلَّذِينَ مِن قَبْلِهِمْ قَرِيبًۭا ۖ ذَاقُوا۟ وَبَالَ أَمْرِهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌۭ', NULL, 28, 219, 7, 547, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 16, 'كَمَثَلِ ٱلشَّيْطَٰنِ إِذْ قَالَ لِلْإِنسَٰنِ ٱكْفُرْ فَلَمَّا كَفَرَ قَالَ إِنِّى بَرِىٓءٌۭ مِّنكَ إِنِّىٓ أَخَافُ ٱللَّهَ رَبَّ ٱلْعَٰلَمِينَ', NULL, 28, 219, 7, 547, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 17, 'فَكَانَ عَٰقِبَتَهُمَآ أَنَّهُمَا فِى ٱلنَّارِ خَٰلِدَيْنِ فِيهَا ۚ وَذَٰلِكَ جَزَٰٓؤُا۟ ٱلظَّٰلِمِينَ', NULL, 28, 219, 7, 548, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 18, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ وَلْتَنظُرْ نَفْسٌۭ مَّا قَدَّمَتْ لِغَدٍۢ ۖ وَٱتَّقُوا۟ ٱللَّهَ ۚ إِنَّ ٱللَّهَ خَبِيرٌۢ بِمَا تَعْمَلُونَ', NULL, 28, 219, 7, 548, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 19, 'وَلَا تَكُونُوا۟ كَٱلَّذِينَ نَسُوا۟ ٱللَّهَ فَأَنسَىٰهُمْ أَنفُسَهُمْ ۚ أُو۟لَٰٓئِكَ هُمُ ٱلْفَٰسِقُونَ', NULL, 28, 219, 7, 548, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 20, 'لَا يَسْتَوِىٓ أَصْحَٰبُ ٱلنَّارِ وَأَصْحَٰبُ ٱلْجَنَّةِ ۚ أَصْحَٰبُ ٱلْجَنَّةِ هُمُ ٱلْفَآئِزُونَ', NULL, 28, 219, 7, 548, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 21, 'لَوْ أَنزَلْنَا هَٰذَا ٱلْقُرْءَانَ عَلَىٰ جَبَلٍۢ لَّرَأَيْتَهُۥ خَٰشِعًۭا مُّتَصَدِّعًۭا مِّنْ خَشْيَةِ ٱللَّهِ ۚ وَتِلْكَ ٱلْأَمْثَٰلُ نَضْرِبُهَا لِلنَّاسِ لَعَلَّهُمْ يَتَفَكَّرُونَ', NULL, 28, 219, 7, 548, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 22, 'هُوَ ٱللَّهُ ٱلَّذِى لَآ إِلَٰهَ إِلَّا هُوَ ۖ عَٰلِمُ ٱلْغَيْبِ وَٱلشَّهَٰدَةِ ۖ هُوَ ٱلرَّحْمَٰنُ ٱلرَّحِيمُ', NULL, 28, 219, 7, 548, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 23, 'هُوَ ٱللَّهُ ٱلَّذِى لَآ إِلَٰهَ إِلَّا هُوَ ٱلْمَلِكُ ٱلْقُدُّوسُ ٱلسَّلَٰمُ ٱلْمُؤْمِنُ ٱلْمُهَيْمِنُ ٱلْعَزِيزُ ٱلْجَبَّارُ ٱلْمُتَكَبِّرُ ۚ سُبْحَٰنَ ٱللَّهِ عَمَّا يُشْرِكُونَ', NULL, 28, 219, 7, 548, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 59), 24, 'هُوَ ٱللَّهُ ٱلْخَٰلِقُ ٱلْبَارِئُ ٱلْمُصَوِّرُ ۖ لَهُ ٱلْأَسْمَآءُ ٱلْحُسْنَىٰ ۚ يُسَبِّحُ لَهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 28, 219, 7, 548, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 60), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَّخِذُوا۟ عَدُوِّى وَعَدُوَّكُمْ أَوْلِيَآءَ تُلْقُونَ إِلَيْهِم بِٱلْمَوَدَّةِ وَقَدْ كَفَرُوا۟ بِمَا جَآءَكُم مِّنَ ٱلْحَقِّ يُخْرِجُونَ ٱلرَّسُولَ وَإِيَّاكُمْ ۙ أَن تُؤْمِنُوا۟ بِٱللَّهِ رَبِّكُمْ إِن كُنتُمْ خَرَجْتُمْ جِهَٰدًۭا فِى سَبِيلِى وَٱبْتِغَآءَ مَرْضَاتِى ۚ تُسِرُّونَ إِلَيْهِم بِٱلْمَوَدَّةِ وَأَنَا۠ أَعْلَمُ بِمَآ أَخْفَيْتُمْ وَمَآ أَعْلَنتُمْ ۚ وَمَن يَفْعَلْهُ مِنكُمْ فَقَدْ ضَلَّ سَوَآءَ ٱلسَّبِيلِ', NULL, 28, 219, 7, 549, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 60), 2, 'إِن يَثْقَفُوكُمْ يَكُونُوا۟ لَكُمْ أَعْدَآءًۭ وَيَبْسُطُوٓا۟ إِلَيْكُمْ أَيْدِيَهُمْ وَأَلْسِنَتَهُم بِٱلسُّوٓءِ وَوَدُّوا۟ لَوْ تَكْفُرُونَ', NULL, 28, 219, 7, 549, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 60), 3, 'لَن تَنفَعَكُمْ أَرْحَامُكُمْ وَلَآ أَوْلَٰدُكُمْ ۚ يَوْمَ ٱلْقِيَٰمَةِ يَفْصِلُ بَيْنَكُمْ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌۭ', NULL, 28, 219, 7, 549, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 60), 4, 'قَدْ كَانَتْ لَكُمْ أُسْوَةٌ حَسَنَةٌۭ فِىٓ إِبْرَٰهِيمَ وَٱلَّذِينَ مَعَهُۥٓ إِذْ قَالُوا۟ لِقَوْمِهِمْ إِنَّا بُرَءَٰٓؤُا۟ مِنكُمْ وَمِمَّا تَعْبُدُونَ مِن دُونِ ٱللَّهِ كَفَرْنَا بِكُمْ وَبَدَا بَيْنَنَا وَبَيْنَكُمُ ٱلْعَدَٰوَةُ وَٱلْبَغْضَآءُ أَبَدًا حَتَّىٰ تُؤْمِنُوا۟ بِٱللَّهِ وَحْدَهُۥٓ إِلَّا قَوْلَ إِبْرَٰهِيمَ لِأَبِيهِ لَأَسْتَغْفِرَنَّ لَكَ وَمَآ أَمْلِكُ لَكَ مِنَ ٱللَّهِ مِن شَىْءٍۢ ۖ رَّبَّنَا عَلَيْكَ تَوَكَّلْنَا وَإِلَيْكَ أَنَبْنَا وَإِلَيْكَ ٱلْمَصِيرُ', NULL, 28, 219, 7, 549, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 60), 5, 'رَبَّنَا لَا تَجْعَلْنَا فِتْنَةًۭ لِّلَّذِينَ كَفَرُوا۟ وَٱغْفِرْ لَنَا رَبَّنَآ ۖ إِنَّكَ أَنتَ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 28, 219, 7, 549, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 60), 6, 'لَقَدْ كَانَ لَكُمْ فِيهِمْ أُسْوَةٌ حَسَنَةٌۭ لِّمَن كَانَ يَرْجُوا۟ ٱللَّهَ وَٱلْيَوْمَ ٱلْءَاخِرَ ۚ وَمَن يَتَوَلَّ فَإِنَّ ٱللَّهَ هُوَ ٱلْغَنِىُّ ٱلْحَمِيدُ', NULL, 28, 219, 7, 550, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 60), 7, '۞ عَسَى ٱللَّهُ أَن يَجْعَلَ بَيْنَكُمْ وَبَيْنَ ٱلَّذِينَ عَادَيْتُم مِّنْهُم مَّوَدَّةًۭ ۚ وَٱللَّهُ قَدِيرٌۭ ۚ وَٱللَّهُ غَفُورٌۭ رَّحِيمٌۭ', NULL, 28, 220, 7, 550, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 60), 8, 'لَّا يَنْهَىٰكُمُ ٱللَّهُ عَنِ ٱلَّذِينَ لَمْ يُقَٰتِلُوكُمْ فِى ٱلدِّينِ وَلَمْ يُخْرِجُوكُم مِّن دِيَٰرِكُمْ أَن تَبَرُّوهُمْ وَتُقْسِطُوٓا۟ إِلَيْهِمْ ۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلْمُقْسِطِينَ', NULL, 28, 220, 7, 550, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 60), 9, 'إِنَّمَا يَنْهَىٰكُمُ ٱللَّهُ عَنِ ٱلَّذِينَ قَٰتَلُوكُمْ فِى ٱلدِّينِ وَأَخْرَجُوكُم مِّن دِيَٰرِكُمْ وَظَٰهَرُوا۟ عَلَىٰٓ إِخْرَاجِكُمْ أَن تَوَلَّوْهُمْ ۚ وَمَن يَتَوَلَّهُمْ فَأُو۟لَٰٓئِكَ هُمُ ٱلظَّٰلِمُونَ', NULL, 28, 220, 7, 550, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 60), 10, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا جَآءَكُمُ ٱلْمُؤْمِنَٰتُ مُهَٰجِرَٰتٍۢ فَٱمْتَحِنُوهُنَّ ۖ ٱللَّهُ أَعْلَمُ بِإِيمَٰنِهِنَّ ۖ فَإِنْ عَلِمْتُمُوهُنَّ مُؤْمِنَٰتٍۢ فَلَا تَرْجِعُوهُنَّ إِلَى ٱلْكُفَّارِ ۖ لَا هُنَّ حِلٌّۭ لَّهُمْ وَلَا هُمْ يَحِلُّونَ لَهُنَّ ۖ وَءَاتُوهُم مَّآ أَنفَقُوا۟ ۚ وَلَا جُنَاحَ عَلَيْكُمْ أَن تَنكِحُوهُنَّ إِذَآ ءَاتَيْتُمُوهُنَّ أُجُورَهُنَّ ۚ وَلَا تُمْسِكُوا۟ بِعِصَمِ ٱلْكَوَافِرِ وَسْـَٔلُوا۟ مَآ أَنفَقْتُمْ وَلْيَسْـَٔلُوا۟ مَآ أَنفَقُوا۟ ۚ ذَٰلِكُمْ حُكْمُ ٱللَّهِ ۖ يَحْكُمُ بَيْنَكُمْ ۚ وَٱللَّهُ عَلِيمٌ حَكِيمٌۭ', NULL, 28, 220, 7, 550, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 60), 11, 'وَإِن فَاتَكُمْ شَىْءٌۭ مِّنْ أَزْوَٰجِكُمْ إِلَى ٱلْكُفَّارِ فَعَاقَبْتُمْ فَـَٔاتُوا۟ ٱلَّذِينَ ذَهَبَتْ أَزْوَٰجُهُم مِّثْلَ مَآ أَنفَقُوا۟ ۚ وَٱتَّقُوا۟ ٱللَّهَ ٱلَّذِىٓ أَنتُم بِهِۦ مُؤْمِنُونَ', NULL, 28, 220, 7, 550, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 60), 12, 'يَٰٓأَيُّهَا ٱلنَّبِىُّ إِذَا جَآءَكَ ٱلْمُؤْمِنَٰتُ يُبَايِعْنَكَ عَلَىٰٓ أَن لَّا يُشْرِكْنَ بِٱللَّهِ شَيْـًۭٔا وَلَا يَسْرِقْنَ وَلَا يَزْنِينَ وَلَا يَقْتُلْنَ أَوْلَٰدَهُنَّ وَلَا يَأْتِينَ بِبُهْتَٰنٍۢ يَفْتَرِينَهُۥ بَيْنَ أَيْدِيهِنَّ وَأَرْجُلِهِنَّ وَلَا يَعْصِينَكَ فِى مَعْرُوفٍۢ ۙ فَبَايِعْهُنَّ وَٱسْتَغْفِرْ لَهُنَّ ٱللَّهَ ۖ إِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌۭ', NULL, 28, 220, 7, 551, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 60), 13, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَوَلَّوْا۟ قَوْمًا غَضِبَ ٱللَّهُ عَلَيْهِمْ قَدْ يَئِسُوا۟ مِنَ ٱلْءَاخِرَةِ كَمَا يَئِسَ ٱلْكُفَّارُ مِنْ أَصْحَٰبِ ٱلْقُبُورِ', NULL, 28, 220, 7, 551, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 61), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ سَبَّحَ لِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۖ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 28, 220, 7, 551, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 61), 2, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لِمَ تَقُولُونَ مَا لَا تَفْعَلُونَ', NULL, 28, 220, 7, 551, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 61), 3, 'كَبُرَ مَقْتًا عِندَ ٱللَّهِ أَن تَقُولُوا۟ مَا لَا تَفْعَلُونَ', NULL, 28, 220, 7, 551, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 61), 4, 'إِنَّ ٱللَّهَ يُحِبُّ ٱلَّذِينَ يُقَٰتِلُونَ فِى سَبِيلِهِۦ صَفًّۭا كَأَنَّهُم بُنْيَٰنٌۭ مَّرْصُوصٌۭ', NULL, 28, 220, 7, 551, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 61), 5, 'وَإِذْ قَالَ مُوسَىٰ لِقَوْمِهِۦ يَٰقَوْمِ لِمَ تُؤْذُونَنِى وَقَد تَّعْلَمُونَ أَنِّى رَسُولُ ٱللَّهِ إِلَيْكُمْ ۖ فَلَمَّا زَاغُوٓا۟ أَزَاغَ ٱللَّهُ قُلُوبَهُمْ ۚ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلْفَٰسِقِينَ', NULL, 28, 220, 7, 551, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 61), 6, 'وَإِذْ قَالَ عِيسَى ٱبْنُ مَرْيَمَ يَٰبَنِىٓ إِسْرَٰٓءِيلَ إِنِّى رَسُولُ ٱللَّهِ إِلَيْكُم مُّصَدِّقًۭا لِّمَا بَيْنَ يَدَىَّ مِنَ ٱلتَّوْرَىٰةِ وَمُبَشِّرًۢا بِرَسُولٍۢ يَأْتِى مِنۢ بَعْدِى ٱسْمُهُۥٓ أَحْمَدُ ۖ فَلَمَّا جَآءَهُم بِٱلْبَيِّنَٰتِ قَالُوا۟ هَٰذَا سِحْرٌۭ مُّبِينٌۭ', NULL, 28, 220, 7, 552, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 61), 7, 'وَمَنْ أَظْلَمُ مِمَّنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ ٱلْكَذِبَ وَهُوَ يُدْعَىٰٓ إِلَى ٱلْإِسْلَٰمِ ۚ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّٰلِمِينَ', NULL, 28, 220, 7, 552, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 61), 8, 'يُرِيدُونَ لِيُطْفِـُٔوا۟ نُورَ ٱللَّهِ بِأَفْوَٰهِهِمْ وَٱللَّهُ مُتِمُّ نُورِهِۦ وَلَوْ كَرِهَ ٱلْكَٰفِرُونَ', NULL, 28, 220, 7, 552, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 61), 9, 'هُوَ ٱلَّذِىٓ أَرْسَلَ رَسُولَهُۥ بِٱلْهُدَىٰ وَدِينِ ٱلْحَقِّ لِيُظْهِرَهُۥ عَلَى ٱلدِّينِ كُلِّهِۦ وَلَوْ كَرِهَ ٱلْمُشْرِكُونَ', NULL, 28, 220, 7, 552, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 61), 10, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ هَلْ أَدُلُّكُمْ عَلَىٰ تِجَٰرَةٍۢ تُنجِيكُم مِّنْ عَذَابٍ أَلِيمٍۢ', NULL, 28, 220, 7, 552, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 61), 11, 'تُؤْمِنُونَ بِٱللَّهِ وَرَسُولِهِۦ وَتُجَٰهِدُونَ فِى سَبِيلِ ٱللَّهِ بِأَمْوَٰلِكُمْ وَأَنفُسِكُمْ ۚ ذَٰلِكُمْ خَيْرٌۭ لَّكُمْ إِن كُنتُمْ تَعْلَمُونَ', NULL, 28, 220, 7, 552, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 61), 12, 'يَغْفِرْ لَكُمْ ذُنُوبَكُمْ وَيُدْخِلْكُمْ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ وَمَسَٰكِنَ طَيِّبَةًۭ فِى جَنَّٰتِ عَدْنٍۢ ۚ ذَٰلِكَ ٱلْفَوْزُ ٱلْعَظِيمُ', NULL, 28, 220, 7, 552, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 61), 13, 'وَأُخْرَىٰ تُحِبُّونَهَا ۖ نَصْرٌۭ مِّنَ ٱللَّهِ وَفَتْحٌۭ قَرِيبٌۭ ۗ وَبَشِّرِ ٱلْمُؤْمِنِينَ', NULL, 28, 220, 7, 552, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 61), 14, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ كُونُوٓا۟ أَنصَارَ ٱللَّهِ كَمَا قَالَ عِيسَى ٱبْنُ مَرْيَمَ لِلْحَوَارِيِّۦنَ مَنْ أَنصَارِىٓ إِلَى ٱللَّهِ ۖ قَالَ ٱلْحَوَارِيُّونَ نَحْنُ أَنصَارُ ٱللَّهِ ۖ فَـَٔامَنَت طَّآئِفَةٌۭ مِّنۢ بَنِىٓ إِسْرَٰٓءِيلَ وَكَفَرَت طَّآئِفَةٌۭ ۖ فَأَيَّدْنَا ٱلَّذِينَ ءَامَنُوا۟ عَلَىٰ عَدُوِّهِمْ فَأَصْبَحُوا۟ ظَٰهِرِينَ', NULL, 28, 220, 7, 552, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 62), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ يُسَبِّحُ لِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ٱلْمَلِكِ ٱلْقُدُّوسِ ٱلْعَزِيزِ ٱلْحَكِيمِ', NULL, 28, 221, 7, 553, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 62), 2, 'هُوَ ٱلَّذِى بَعَثَ فِى ٱلْأُمِّيِّۦنَ رَسُولًۭا مِّنْهُمْ يَتْلُوا۟ عَلَيْهِمْ ءَايَٰتِهِۦ وَيُزَكِّيهِمْ وَيُعَلِّمُهُمُ ٱلْكِتَٰبَ وَٱلْحِكْمَةَ وَإِن كَانُوا۟ مِن قَبْلُ لَفِى ضَلَٰلٍۢ مُّبِينٍۢ', NULL, 28, 221, 7, 553, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 62), 3, 'وَءَاخَرِينَ مِنْهُمْ لَمَّا يَلْحَقُوا۟ بِهِمْ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 28, 221, 7, 553, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 62), 4, 'ذَٰلِكَ فَضْلُ ٱللَّهِ يُؤْتِيهِ مَن يَشَآءُ ۚ وَٱللَّهُ ذُو ٱلْفَضْلِ ٱلْعَظِيمِ', NULL, 28, 221, 7, 553, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 62), 5, 'مَثَلُ ٱلَّذِينَ حُمِّلُوا۟ ٱلتَّوْرَىٰةَ ثُمَّ لَمْ يَحْمِلُوهَا كَمَثَلِ ٱلْحِمَارِ يَحْمِلُ أَسْفَارًۢا ۚ بِئْسَ مَثَلُ ٱلْقَوْمِ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِ ٱللَّهِ ۚ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّٰلِمِينَ', NULL, 28, 221, 7, 553, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 62), 6, 'قُلْ يَٰٓأَيُّهَا ٱلَّذِينَ هَادُوٓا۟ إِن زَعَمْتُمْ أَنَّكُمْ أَوْلِيَآءُ لِلَّهِ مِن دُونِ ٱلنَّاسِ فَتَمَنَّوُا۟ ٱلْمَوْتَ إِن كُنتُمْ صَٰدِقِينَ', NULL, 28, 221, 7, 553, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 62), 7, 'وَلَا يَتَمَنَّوْنَهُۥٓ أَبَدًۢا بِمَا قَدَّمَتْ أَيْدِيهِمْ ۚ وَٱللَّهُ عَلِيمٌۢ بِٱلظَّٰلِمِينَ', NULL, 28, 221, 7, 553, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 62), 8, 'قُلْ إِنَّ ٱلْمَوْتَ ٱلَّذِى تَفِرُّونَ مِنْهُ فَإِنَّهُۥ مُلَٰقِيكُمْ ۖ ثُمَّ تُرَدُّونَ إِلَىٰ عَٰلِمِ ٱلْغَيْبِ وَٱلشَّهَٰدَةِ فَيُنَبِّئُكُم بِمَا كُنتُمْ تَعْمَلُونَ', NULL, 28, 221, 7, 553, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 62), 9, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا نُودِىَ لِلصَّلَوٰةِ مِن يَوْمِ ٱلْجُمُعَةِ فَٱسْعَوْا۟ إِلَىٰ ذِكْرِ ٱللَّهِ وَذَرُوا۟ ٱلْبَيْعَ ۚ ذَٰلِكُمْ خَيْرٌۭ لَّكُمْ إِن كُنتُمْ تَعْلَمُونَ', NULL, 28, 221, 7, 554, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 62), 10, 'فَإِذَا قُضِيَتِ ٱلصَّلَوٰةُ فَٱنتَشِرُوا۟ فِى ٱلْأَرْضِ وَٱبْتَغُوا۟ مِن فَضْلِ ٱللَّهِ وَٱذْكُرُوا۟ ٱللَّهَ كَثِيرًۭا لَّعَلَّكُمْ تُفْلِحُونَ', NULL, 28, 221, 7, 554, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 62), 11, 'وَإِذَا رَأَوْا۟ تِجَٰرَةً أَوْ لَهْوًا ٱنفَضُّوٓا۟ إِلَيْهَا وَتَرَكُوكَ قَآئِمًۭا ۚ قُلْ مَا عِندَ ٱللَّهِ خَيْرٌۭ مِّنَ ٱللَّهْوِ وَمِنَ ٱلتِّجَٰرَةِ ۚ وَٱللَّهُ خَيْرُ ٱلرَّٰزِقِينَ', NULL, 28, 221, 7, 554, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 63), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ إِذَا جَآءَكَ ٱلْمُنَٰفِقُونَ قَالُوا۟ نَشْهَدُ إِنَّكَ لَرَسُولُ ٱللَّهِ ۗ وَٱللَّهُ يَعْلَمُ إِنَّكَ لَرَسُولُهُۥ وَٱللَّهُ يَشْهَدُ إِنَّ ٱلْمُنَٰفِقِينَ لَكَٰذِبُونَ', NULL, 28, 221, 7, 554, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 63), 2, 'ٱتَّخَذُوٓا۟ أَيْمَٰنَهُمْ جُنَّةًۭ فَصَدُّوا۟ عَن سَبِيلِ ٱللَّهِ ۚ إِنَّهُمْ سَآءَ مَا كَانُوا۟ يَعْمَلُونَ', NULL, 28, 221, 7, 554, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 63), 3, 'ذَٰلِكَ بِأَنَّهُمْ ءَامَنُوا۟ ثُمَّ كَفَرُوا۟ فَطُبِعَ عَلَىٰ قُلُوبِهِمْ فَهُمْ لَا يَفْقَهُونَ', NULL, 28, 221, 7, 554, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 63), 4, '۞ وَإِذَا رَأَيْتَهُمْ تُعْجِبُكَ أَجْسَامُهُمْ ۖ وَإِن يَقُولُوا۟ تَسْمَعْ لِقَوْلِهِمْ ۖ كَأَنَّهُمْ خُشُبٌۭ مُّسَنَّدَةٌۭ ۖ يَحْسَبُونَ كُلَّ صَيْحَةٍ عَلَيْهِمْ ۚ هُمُ ٱلْعَدُوُّ فَٱحْذَرْهُمْ ۚ قَٰتَلَهُمُ ٱللَّهُ ۖ أَنَّىٰ يُؤْفَكُونَ', NULL, 28, 222, 7, 554, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 63), 5, 'وَإِذَا قِيلَ لَهُمْ تَعَالَوْا۟ يَسْتَغْفِرْ لَكُمْ رَسُولُ ٱللَّهِ لَوَّوْا۟ رُءُوسَهُمْ وَرَأَيْتَهُمْ يَصُدُّونَ وَهُم مُّسْتَكْبِرُونَ', NULL, 28, 222, 7, 555, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 63), 6, 'سَوَآءٌ عَلَيْهِمْ أَسْتَغْفَرْتَ لَهُمْ أَمْ لَمْ تَسْتَغْفِرْ لَهُمْ لَن يَغْفِرَ ٱللَّهُ لَهُمْ ۚ إِنَّ ٱللَّهَ لَا يَهْدِى ٱلْقَوْمَ ٱلْفَٰسِقِينَ', NULL, 28, 222, 7, 555, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 63), 7, 'هُمُ ٱلَّذِينَ يَقُولُونَ لَا تُنفِقُوا۟ عَلَىٰ مَنْ عِندَ رَسُولِ ٱللَّهِ حَتَّىٰ يَنفَضُّوا۟ ۗ وَلِلَّهِ خَزَآئِنُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَلَٰكِنَّ ٱلْمُنَٰفِقِينَ لَا يَفْقَهُونَ', NULL, 28, 222, 7, 555, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 63), 8, 'يَقُولُونَ لَئِن رَّجَعْنَآ إِلَى ٱلْمَدِينَةِ لَيُخْرِجَنَّ ٱلْأَعَزُّ مِنْهَا ٱلْأَذَلَّ ۚ وَلِلَّهِ ٱلْعِزَّةُ وَلِرَسُولِهِۦ وَلِلْمُؤْمِنِينَ وَلَٰكِنَّ ٱلْمُنَٰفِقِينَ لَا يَعْلَمُونَ', NULL, 28, 222, 7, 555, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 63), 9, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تُلْهِكُمْ أَمْوَٰلُكُمْ وَلَآ أَوْلَٰدُكُمْ عَن ذِكْرِ ٱللَّهِ ۚ وَمَن يَفْعَلْ ذَٰلِكَ فَأُو۟لَٰٓئِكَ هُمُ ٱلْخَٰسِرُونَ', NULL, 28, 222, 7, 555, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 63), 10, 'وَأَنفِقُوا۟ مِن مَّا رَزَقْنَٰكُم مِّن قَبْلِ أَن يَأْتِىَ أَحَدَكُمُ ٱلْمَوْتُ فَيَقُولَ رَبِّ لَوْلَآ أَخَّرْتَنِىٓ إِلَىٰٓ أَجَلٍۢ قَرِيبٍۢ فَأَصَّدَّقَ وَأَكُن مِّنَ ٱلصَّٰلِحِينَ', NULL, 28, 222, 7, 555, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 63), 11, 'وَلَن يُؤَخِّرَ ٱللَّهُ نَفْسًا إِذَا جَآءَ أَجَلُهَا ۚ وَٱللَّهُ خَبِيرٌۢ بِمَا تَعْمَلُونَ', NULL, 28, 222, 7, 555, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ يُسَبِّحُ لِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۖ لَهُ ٱلْمُلْكُ وَلَهُ ٱلْحَمْدُ ۖ وَهُوَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌ', NULL, 28, 222, 7, 556, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 2, 'هُوَ ٱلَّذِى خَلَقَكُمْ فَمِنكُمْ كَافِرٌۭ وَمِنكُم مُّؤْمِنٌۭ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌ', NULL, 28, 222, 7, 556, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 3, 'خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ وَصَوَّرَكُمْ فَأَحْسَنَ صُوَرَكُمْ ۖ وَإِلَيْهِ ٱلْمَصِيرُ', NULL, 28, 222, 7, 556, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 4, 'يَعْلَمُ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَيَعْلَمُ مَا تُسِرُّونَ وَمَا تُعْلِنُونَ ۚ وَٱللَّهُ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ', NULL, 28, 222, 7, 556, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 5, 'أَلَمْ يَأْتِكُمْ نَبَؤُا۟ ٱلَّذِينَ كَفَرُوا۟ مِن قَبْلُ فَذَاقُوا۟ وَبَالَ أَمْرِهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌۭ', NULL, 28, 222, 7, 556, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 6, 'ذَٰلِكَ بِأَنَّهُۥ كَانَت تَّأْتِيهِمْ رُسُلُهُم بِٱلْبَيِّنَٰتِ فَقَالُوٓا۟ أَبَشَرٌۭ يَهْدُونَنَا فَكَفَرُوا۟ وَتَوَلَّوا۟ ۚ وَّٱسْتَغْنَى ٱللَّهُ ۚ وَٱللَّهُ غَنِىٌّ حَمِيدٌۭ', NULL, 28, 222, 7, 556, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 7, 'زَعَمَ ٱلَّذِينَ كَفَرُوٓا۟ أَن لَّن يُبْعَثُوا۟ ۚ قُلْ بَلَىٰ وَرَبِّى لَتُبْعَثُنَّ ثُمَّ لَتُنَبَّؤُنَّ بِمَا عَمِلْتُمْ ۚ وَذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٌۭ', NULL, 28, 222, 7, 556, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 8, 'فَـَٔامِنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ وَٱلنُّورِ ٱلَّذِىٓ أَنزَلْنَا ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌۭ', NULL, 28, 222, 7, 556, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 9, 'يَوْمَ يَجْمَعُكُمْ لِيَوْمِ ٱلْجَمْعِ ۖ ذَٰلِكَ يَوْمُ ٱلتَّغَابُنِ ۗ وَمَن يُؤْمِنۢ بِٱللَّهِ وَيَعْمَلْ صَٰلِحًۭا يُكَفِّرْ عَنْهُ سَيِّـَٔاتِهِۦ وَيُدْخِلْهُ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَآ أَبَدًۭا ۚ ذَٰلِكَ ٱلْفَوْزُ ٱلْعَظِيمُ', NULL, 28, 222, 7, 556, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 10, 'وَٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَٰتِنَآ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ خَٰلِدِينَ فِيهَا ۖ وَبِئْسَ ٱلْمَصِيرُ', NULL, 28, 222, 7, 557, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 11, 'مَآ أَصَابَ مِن مُّصِيبَةٍ إِلَّا بِإِذْنِ ٱللَّهِ ۗ وَمَن يُؤْمِنۢ بِٱللَّهِ يَهْدِ قَلْبَهُۥ ۚ وَٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمٌۭ', NULL, 28, 222, 7, 557, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 12, 'وَأَطِيعُوا۟ ٱللَّهَ وَأَطِيعُوا۟ ٱلرَّسُولَ ۚ فَإِن تَوَلَّيْتُمْ فَإِنَّمَا عَلَىٰ رَسُولِنَا ٱلْبَلَٰغُ ٱلْمُبِينُ', NULL, 28, 222, 7, 557, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 13, 'ٱللَّهُ لَآ إِلَٰهَ إِلَّا هُوَ ۚ وَعَلَى ٱللَّهِ فَلْيَتَوَكَّلِ ٱلْمُؤْمِنُونَ', NULL, 28, 222, 7, 557, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 14, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِنَّ مِنْ أَزْوَٰجِكُمْ وَأَوْلَٰدِكُمْ عَدُوًّۭا لَّكُمْ فَٱحْذَرُوهُمْ ۚ وَإِن تَعْفُوا۟ وَتَصْفَحُوا۟ وَتَغْفِرُوا۟ فَإِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌ', NULL, 28, 222, 7, 557, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 15, 'إِنَّمَآ أَمْوَٰلُكُمْ وَأَوْلَٰدُكُمْ فِتْنَةٌۭ ۚ وَٱللَّهُ عِندَهُۥٓ أَجْرٌ عَظِيمٌۭ', NULL, 28, 222, 7, 557, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 16, 'فَٱتَّقُوا۟ ٱللَّهَ مَا ٱسْتَطَعْتُمْ وَٱسْمَعُوا۟ وَأَطِيعُوا۟ وَأَنفِقُوا۟ خَيْرًۭا لِّأَنفُسِكُمْ ۗ وَمَن يُوقَ شُحَّ نَفْسِهِۦ فَأُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ', NULL, 28, 222, 7, 557, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 17, 'إِن تُقْرِضُوا۟ ٱللَّهَ قَرْضًا حَسَنًۭا يُضَٰعِفْهُ لَكُمْ وَيَغْفِرْ لَكُمْ ۚ وَٱللَّهُ شَكُورٌ حَلِيمٌ', NULL, 28, 222, 7, 557, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 64), 18, 'عَٰلِمُ ٱلْغَيْبِ وَٱلشَّهَٰدَةِ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 28, 222, 7, 557, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 65), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ يَٰٓأَيُّهَا ٱلنَّبِىُّ إِذَا طَلَّقْتُمُ ٱلنِّسَآءَ فَطَلِّقُوهُنَّ لِعِدَّتِهِنَّ وَأَحْصُوا۟ ٱلْعِدَّةَ ۖ وَٱتَّقُوا۟ ٱللَّهَ رَبَّكُمْ ۖ لَا تُخْرِجُوهُنَّ مِنۢ بُيُوتِهِنَّ وَلَا يَخْرُجْنَ إِلَّآ أَن يَأْتِينَ بِفَٰحِشَةٍۢ مُّبَيِّنَةٍۢ ۚ وَتِلْكَ حُدُودُ ٱللَّهِ ۚ وَمَن يَتَعَدَّ حُدُودَ ٱللَّهِ فَقَدْ ظَلَمَ نَفْسَهُۥ ۚ لَا تَدْرِى لَعَلَّ ٱللَّهَ يُحْدِثُ بَعْدَ ذَٰلِكَ أَمْرًۭا', NULL, 28, 223, 7, 558, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 65), 2, 'فَإِذَا بَلَغْنَ أَجَلَهُنَّ فَأَمْسِكُوهُنَّ بِمَعْرُوفٍ أَوْ فَارِقُوهُنَّ بِمَعْرُوفٍۢ وَأَشْهِدُوا۟ ذَوَىْ عَدْلٍۢ مِّنكُمْ وَأَقِيمُوا۟ ٱلشَّهَٰدَةَ لِلَّهِ ۚ ذَٰلِكُمْ يُوعَظُ بِهِۦ مَن كَانَ يُؤْمِنُ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ ۚ وَمَن يَتَّقِ ٱللَّهَ يَجْعَل لَّهُۥ مَخْرَجًۭا', NULL, 28, 223, 7, 558, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 65), 3, 'وَيَرْزُقْهُ مِنْ حَيْثُ لَا يَحْتَسِبُ ۚ وَمَن يَتَوَكَّلْ عَلَى ٱللَّهِ فَهُوَ حَسْبُهُۥٓ ۚ إِنَّ ٱللَّهَ بَٰلِغُ أَمْرِهِۦ ۚ قَدْ جَعَلَ ٱللَّهُ لِكُلِّ شَىْءٍۢ قَدْرًۭا', NULL, 28, 223, 7, 558, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 65), 4, 'وَٱلَّٰٓـِٔى يَئِسْنَ مِنَ ٱلْمَحِيضِ مِن نِّسَآئِكُمْ إِنِ ٱرْتَبْتُمْ فَعِدَّتُهُنَّ ثَلَٰثَةُ أَشْهُرٍۢ وَٱلَّٰٓـِٔى لَمْ يَحِضْنَ ۚ وَأُو۟لَٰتُ ٱلْأَحْمَالِ أَجَلُهُنَّ أَن يَضَعْنَ حَمْلَهُنَّ ۚ وَمَن يَتَّقِ ٱللَّهَ يَجْعَل لَّهُۥ مِنْ أَمْرِهِۦ يُسْرًۭا', NULL, 28, 223, 7, 558, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 65), 5, 'ذَٰلِكَ أَمْرُ ٱللَّهِ أَنزَلَهُۥٓ إِلَيْكُمْ ۚ وَمَن يَتَّقِ ٱللَّهَ يُكَفِّرْ عَنْهُ سَيِّـَٔاتِهِۦ وَيُعْظِمْ لَهُۥٓ أَجْرًا', NULL, 28, 223, 7, 558, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 65), 6, 'أَسْكِنُوهُنَّ مِنْ حَيْثُ سَكَنتُم مِّن وُجْدِكُمْ وَلَا تُضَآرُّوهُنَّ لِتُضَيِّقُوا۟ عَلَيْهِنَّ ۚ وَإِن كُنَّ أُو۟لَٰتِ حَمْلٍۢ فَأَنفِقُوا۟ عَلَيْهِنَّ حَتَّىٰ يَضَعْنَ حَمْلَهُنَّ ۚ فَإِنْ أَرْضَعْنَ لَكُمْ فَـَٔاتُوهُنَّ أُجُورَهُنَّ ۖ وَأْتَمِرُوا۟ بَيْنَكُم بِمَعْرُوفٍۢ ۖ وَإِن تَعَاسَرْتُمْ فَسَتُرْضِعُ لَهُۥٓ أُخْرَىٰ', NULL, 28, 223, 7, 559, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 65), 7, 'لِيُنفِقْ ذُو سَعَةٍۢ مِّن سَعَتِهِۦ ۖ وَمَن قُدِرَ عَلَيْهِ رِزْقُهُۥ فَلْيُنفِقْ مِمَّآ ءَاتَىٰهُ ٱللَّهُ ۚ لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا مَآ ءَاتَىٰهَا ۚ سَيَجْعَلُ ٱللَّهُ بَعْدَ عُسْرٍۢ يُسْرًۭا', NULL, 28, 223, 7, 559, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 65), 8, 'وَكَأَيِّن مِّن قَرْيَةٍ عَتَتْ عَنْ أَمْرِ رَبِّهَا وَرُسُلِهِۦ فَحَاسَبْنَٰهَا حِسَابًۭا شَدِيدًۭا وَعَذَّبْنَٰهَا عَذَابًۭا نُّكْرًۭا', NULL, 28, 223, 7, 559, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 65), 9, 'فَذَاقَتْ وَبَالَ أَمْرِهَا وَكَانَ عَٰقِبَةُ أَمْرِهَا خُسْرًا', NULL, 28, 223, 7, 559, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 65), 10, 'أَعَدَّ ٱللَّهُ لَهُمْ عَذَابًۭا شَدِيدًۭا ۖ فَٱتَّقُوا۟ ٱللَّهَ يَٰٓأُو۟لِى ٱلْأَلْبَٰبِ ٱلَّذِينَ ءَامَنُوا۟ ۚ قَدْ أَنزَلَ ٱللَّهُ إِلَيْكُمْ ذِكْرًۭا', NULL, 28, 223, 7, 559, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 65), 11, 'رَّسُولًۭا يَتْلُوا۟ عَلَيْكُمْ ءَايَٰتِ ٱللَّهِ مُبَيِّنَٰتٍۢ لِّيُخْرِجَ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ مِنَ ٱلظُّلُمَٰتِ إِلَى ٱلنُّورِ ۚ وَمَن يُؤْمِنۢ بِٱللَّهِ وَيَعْمَلْ صَٰلِحًۭا يُدْخِلْهُ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَآ أَبَدًۭا ۖ قَدْ أَحْسَنَ ٱللَّهُ لَهُۥ رِزْقًا', NULL, 28, 223, 7, 559, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 65), 12, 'ٱللَّهُ ٱلَّذِى خَلَقَ سَبْعَ سَمَٰوَٰتٍۢ وَمِنَ ٱلْأَرْضِ مِثْلَهُنَّ يَتَنَزَّلُ ٱلْأَمْرُ بَيْنَهُنَّ لِتَعْلَمُوٓا۟ أَنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ وَأَنَّ ٱللَّهَ قَدْ أَحَاطَ بِكُلِّ شَىْءٍ عِلْمًۢا', NULL, 28, 223, 7, 559, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 66), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ يَٰٓأَيُّهَا ٱلنَّبِىُّ لِمَ تُحَرِّمُ مَآ أَحَلَّ ٱللَّهُ لَكَ ۖ تَبْتَغِى مَرْضَاتَ أَزْوَٰجِكَ ۚ وَٱللَّهُ غَفُورٌۭ رَّحِيمٌۭ', NULL, 28, 224, 7, 560, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 66), 2, 'قَدْ فَرَضَ ٱللَّهُ لَكُمْ تَحِلَّةَ أَيْمَٰنِكُمْ ۚ وَٱللَّهُ مَوْلَىٰكُمْ ۖ وَهُوَ ٱلْعَلِيمُ ٱلْحَكِيمُ', NULL, 28, 224, 7, 560, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 66), 3, 'وَإِذْ أَسَرَّ ٱلنَّبِىُّ إِلَىٰ بَعْضِ أَزْوَٰجِهِۦ حَدِيثًۭا فَلَمَّا نَبَّأَتْ بِهِۦ وَأَظْهَرَهُ ٱللَّهُ عَلَيْهِ عَرَّفَ بَعْضَهُۥ وَأَعْرَضَ عَنۢ بَعْضٍۢ ۖ فَلَمَّا نَبَّأَهَا بِهِۦ قَالَتْ مَنْ أَنۢبَأَكَ هَٰذَا ۖ قَالَ نَبَّأَنِىَ ٱلْعَلِيمُ ٱلْخَبِيرُ', NULL, 28, 224, 7, 560, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 66), 4, 'إِن تَتُوبَآ إِلَى ٱللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا ۖ وَإِن تَظَٰهَرَا عَلَيْهِ فَإِنَّ ٱللَّهَ هُوَ مَوْلَىٰهُ وَجِبْرِيلُ وَصَٰلِحُ ٱلْمُؤْمِنِينَ ۖ وَٱلْمَلَٰٓئِكَةُ بَعْدَ ذَٰلِكَ ظَهِيرٌ', NULL, 28, 224, 7, 560, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 66), 5, 'عَسَىٰ رَبُّهُۥٓ إِن طَلَّقَكُنَّ أَن يُبْدِلَهُۥٓ أَزْوَٰجًا خَيْرًۭا مِّنكُنَّ مُسْلِمَٰتٍۢ مُّؤْمِنَٰتٍۢ قَٰنِتَٰتٍۢ تَٰٓئِبَٰتٍ عَٰبِدَٰتٍۢ سَٰٓئِحَٰتٍۢ ثَيِّبَٰتٍۢ وَأَبْكَارًۭا', NULL, 28, 224, 7, 560, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 66), 6, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ قُوٓا۟ أَنفُسَكُمْ وَأَهْلِيكُمْ نَارًۭا وَقُودُهَا ٱلنَّاسُ وَٱلْحِجَارَةُ عَلَيْهَا مَلَٰٓئِكَةٌ غِلَاظٌۭ شِدَادٌۭ لَّا يَعْصُونَ ٱللَّهَ مَآ أَمَرَهُمْ وَيَفْعَلُونَ مَا يُؤْمَرُونَ', NULL, 28, 224, 7, 560, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 66), 7, 'يَٰٓأَيُّهَا ٱلَّذِينَ كَفَرُوا۟ لَا تَعْتَذِرُوا۟ ٱلْيَوْمَ ۖ إِنَّمَا تُجْزَوْنَ مَا كُنتُمْ تَعْمَلُونَ', NULL, 28, 224, 7, 560, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 66), 8, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ تُوبُوٓا۟ إِلَى ٱللَّهِ تَوْبَةًۭ نَّصُوحًا عَسَىٰ رَبُّكُمْ أَن يُكَفِّرَ عَنكُمْ سَيِّـَٔاتِكُمْ وَيُدْخِلَكُمْ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ يَوْمَ لَا يُخْزِى ٱللَّهُ ٱلنَّبِىَّ وَٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ ۖ نُورُهُمْ يَسْعَىٰ بَيْنَ أَيْدِيهِمْ وَبِأَيْمَٰنِهِمْ يَقُولُونَ رَبَّنَآ أَتْمِمْ لَنَا نُورَنَا وَٱغْفِرْ لَنَآ ۖ إِنَّكَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ', NULL, 28, 224, 7, 561, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 66), 9, 'يَٰٓأَيُّهَا ٱلنَّبِىُّ جَٰهِدِ ٱلْكُفَّارَ وَٱلْمُنَٰفِقِينَ وَٱغْلُظْ عَلَيْهِمْ ۚ وَمَأْوَىٰهُمْ جَهَنَّمُ ۖ وَبِئْسَ ٱلْمَصِيرُ', NULL, 28, 224, 7, 561, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 66), 10, 'ضَرَبَ ٱللَّهُ مَثَلًۭا لِّلَّذِينَ كَفَرُوا۟ ٱمْرَأَتَ نُوحٍۢ وَٱمْرَأَتَ لُوطٍۢ ۖ كَانَتَا تَحْتَ عَبْدَيْنِ مِنْ عِبَادِنَا صَٰلِحَيْنِ فَخَانَتَاهُمَا فَلَمْ يُغْنِيَا عَنْهُمَا مِنَ ٱللَّهِ شَيْـًۭٔا وَقِيلَ ٱدْخُلَا ٱلنَّارَ مَعَ ٱلدَّٰخِلِينَ', NULL, 28, 224, 7, 561, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 66), 11, 'وَضَرَبَ ٱللَّهُ مَثَلًۭا لِّلَّذِينَ ءَامَنُوا۟ ٱمْرَأَتَ فِرْعَوْنَ إِذْ قَالَتْ رَبِّ ٱبْنِ لِى عِندَكَ بَيْتًۭا فِى ٱلْجَنَّةِ وَنَجِّنِى مِن فِرْعَوْنَ وَعَمَلِهِۦ وَنَجِّنِى مِنَ ٱلْقَوْمِ ٱلظَّٰلِمِينَ', NULL, 28, 224, 7, 561, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 66), 12, 'وَمَرْيَمَ ٱبْنَتَ عِمْرَٰنَ ٱلَّتِىٓ أَحْصَنَتْ فَرْجَهَا فَنَفَخْنَا فِيهِ مِن رُّوحِنَا وَصَدَّقَتْ بِكَلِمَٰتِ رَبِّهَا وَكُتُبِهِۦ وَكَانَتْ مِنَ ٱلْقَٰنِتِينَ', NULL, 28, 224, 7, 561, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ تَبَٰرَكَ ٱلَّذِى بِيَدِهِ ٱلْمُلْكُ وَهُوَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌ', NULL, 29, 225, 7, 562, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 2, 'ٱلَّذِى خَلَقَ ٱلْمَوْتَ وَٱلْحَيَوٰةَ لِيَبْلُوَكُمْ أَيُّكُمْ أَحْسَنُ عَمَلًۭا ۚ وَهُوَ ٱلْعَزِيزُ ٱلْغَفُورُ', NULL, 29, 225, 7, 562, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 3, 'ٱلَّذِى خَلَقَ سَبْعَ سَمَٰوَٰتٍۢ طِبَاقًۭا ۖ مَّا تَرَىٰ فِى خَلْقِ ٱلرَّحْمَٰنِ مِن تَفَٰوُتٍۢ ۖ فَٱرْجِعِ ٱلْبَصَرَ هَلْ تَرَىٰ مِن فُطُورٍۢ', NULL, 29, 225, 7, 562, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 4, 'ثُمَّ ٱرْجِعِ ٱلْبَصَرَ كَرَّتَيْنِ يَنقَلِبْ إِلَيْكَ ٱلْبَصَرُ خَاسِئًۭا وَهُوَ حَسِيرٌۭ', NULL, 29, 225, 7, 562, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 5, 'وَلَقَدْ زَيَّنَّا ٱلسَّمَآءَ ٱلدُّنْيَا بِمَصَٰبِيحَ وَجَعَلْنَٰهَا رُجُومًۭا لِّلشَّيَٰطِينِ ۖ وَأَعْتَدْنَا لَهُمْ عَذَابَ ٱلسَّعِيرِ', NULL, 29, 225, 7, 562, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 6, 'وَلِلَّذِينَ كَفَرُوا۟ بِرَبِّهِمْ عَذَابُ جَهَنَّمَ ۖ وَبِئْسَ ٱلْمَصِيرُ', NULL, 29, 225, 7, 562, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 7, 'إِذَآ أُلْقُوا۟ فِيهَا سَمِعُوا۟ لَهَا شَهِيقًۭا وَهِىَ تَفُورُ', NULL, 29, 225, 7, 562, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 8, 'تَكَادُ تَمَيَّزُ مِنَ ٱلْغَيْظِ ۖ كُلَّمَآ أُلْقِىَ فِيهَا فَوْجٌۭ سَأَلَهُمْ خَزَنَتُهَآ أَلَمْ يَأْتِكُمْ نَذِيرٌۭ', NULL, 29, 225, 7, 562, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 9, 'قَالُوا۟ بَلَىٰ قَدْ جَآءَنَا نَذِيرٌۭ فَكَذَّبْنَا وَقُلْنَا مَا نَزَّلَ ٱللَّهُ مِن شَىْءٍ إِنْ أَنتُمْ إِلَّا فِى ضَلَٰلٍۢ كَبِيرٍۢ', NULL, 29, 225, 7, 562, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 10, 'وَقَالُوا۟ لَوْ كُنَّا نَسْمَعُ أَوْ نَعْقِلُ مَا كُنَّا فِىٓ أَصْحَٰبِ ٱلسَّعِيرِ', NULL, 29, 225, 7, 562, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 11, 'فَٱعْتَرَفُوا۟ بِذَنۢبِهِمْ فَسُحْقًۭا لِّأَصْحَٰبِ ٱلسَّعِيرِ', NULL, 29, 225, 7, 562, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 12, 'إِنَّ ٱلَّذِينَ يَخْشَوْنَ رَبَّهُم بِٱلْغَيْبِ لَهُم مَّغْفِرَةٌۭ وَأَجْرٌۭ كَبِيرٌۭ', NULL, 29, 225, 7, 562, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 13, 'وَأَسِرُّوا۟ قَوْلَكُمْ أَوِ ٱجْهَرُوا۟ بِهِۦٓ ۖ إِنَّهُۥ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ', NULL, 29, 225, 7, 563, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 14, 'أَلَا يَعْلَمُ مَنْ خَلَقَ وَهُوَ ٱللَّطِيفُ ٱلْخَبِيرُ', NULL, 29, 225, 7, 563, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 15, 'هُوَ ٱلَّذِى جَعَلَ لَكُمُ ٱلْأَرْضَ ذَلُولًۭا فَٱمْشُوا۟ فِى مَنَاكِبِهَا وَكُلُوا۟ مِن رِّزْقِهِۦ ۖ وَإِلَيْهِ ٱلنُّشُورُ', NULL, 29, 225, 7, 563, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 16, 'ءَأَمِنتُم مَّن فِى ٱلسَّمَآءِ أَن يَخْسِفَ بِكُمُ ٱلْأَرْضَ فَإِذَا هِىَ تَمُورُ', NULL, 29, 225, 7, 563, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 17, 'أَمْ أَمِنتُم مَّن فِى ٱلسَّمَآءِ أَن يُرْسِلَ عَلَيْكُمْ حَاصِبًۭا ۖ فَسَتَعْلَمُونَ كَيْفَ نَذِيرِ', NULL, 29, 225, 7, 563, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 18, 'وَلَقَدْ كَذَّبَ ٱلَّذِينَ مِن قَبْلِهِمْ فَكَيْفَ كَانَ نَكِيرِ', NULL, 29, 225, 7, 563, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 19, 'أَوَلَمْ يَرَوْا۟ إِلَى ٱلطَّيْرِ فَوْقَهُمْ صَٰٓفَّٰتٍۢ وَيَقْبِضْنَ ۚ مَا يُمْسِكُهُنَّ إِلَّا ٱلرَّحْمَٰنُ ۚ إِنَّهُۥ بِكُلِّ شَىْءٍۭ بَصِيرٌ', NULL, 29, 225, 7, 563, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 20, 'أَمَّنْ هَٰذَا ٱلَّذِى هُوَ جُندٌۭ لَّكُمْ يَنصُرُكُم مِّن دُونِ ٱلرَّحْمَٰنِ ۚ إِنِ ٱلْكَٰفِرُونَ إِلَّا فِى غُرُورٍ', NULL, 29, 225, 7, 563, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 21, 'أَمَّنْ هَٰذَا ٱلَّذِى يَرْزُقُكُمْ إِنْ أَمْسَكَ رِزْقَهُۥ ۚ بَل لَّجُّوا۟ فِى عُتُوٍّۢ وَنُفُورٍ', NULL, 29, 225, 7, 563, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 22, 'أَفَمَن يَمْشِى مُكِبًّا عَلَىٰ وَجْهِهِۦٓ أَهْدَىٰٓ أَمَّن يَمْشِى سَوِيًّا عَلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ', NULL, 29, 225, 7, 563, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 23, 'قُلْ هُوَ ٱلَّذِىٓ أَنشَأَكُمْ وَجَعَلَ لَكُمُ ٱلسَّمْعَ وَٱلْأَبْصَٰرَ وَٱلْأَفْـِٔدَةَ ۖ قَلِيلًۭا مَّا تَشْكُرُونَ', NULL, 29, 225, 7, 563, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 24, 'قُلْ هُوَ ٱلَّذِى ذَرَأَكُمْ فِى ٱلْأَرْضِ وَإِلَيْهِ تُحْشَرُونَ', NULL, 29, 225, 7, 563, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 25, 'وَيَقُولُونَ مَتَىٰ هَٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَٰدِقِينَ', NULL, 29, 225, 7, 563, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 26, 'قُلْ إِنَّمَا ٱلْعِلْمُ عِندَ ٱللَّهِ وَإِنَّمَآ أَنَا۠ نَذِيرٌۭ مُّبِينٌۭ', NULL, 29, 225, 7, 563, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 27, 'فَلَمَّا رَأَوْهُ زُلْفَةًۭ سِيٓـَٔتْ وُجُوهُ ٱلَّذِينَ كَفَرُوا۟ وَقِيلَ هَٰذَا ٱلَّذِى كُنتُم بِهِۦ تَدَّعُونَ', NULL, 29, 225, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 28, 'قُلْ أَرَءَيْتُمْ إِنْ أَهْلَكَنِىَ ٱللَّهُ وَمَن مَّعِىَ أَوْ رَحِمَنَا فَمَن يُجِيرُ ٱلْكَٰفِرِينَ مِنْ عَذَابٍ أَلِيمٍۢ', NULL, 29, 225, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 29, 'قُلْ هُوَ ٱلرَّحْمَٰنُ ءَامَنَّا بِهِۦ وَعَلَيْهِ تَوَكَّلْنَا ۖ فَسَتَعْلَمُونَ مَنْ هُوَ فِى ضَلَٰلٍۢ مُّبِينٍۢ', NULL, 29, 225, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 67), 30, 'قُلْ أَرَءَيْتُمْ إِنْ أَصْبَحَ مَآؤُكُمْ غَوْرًۭا فَمَن يَأْتِيكُم بِمَآءٍۢ مَّعِينٍۭ', NULL, 29, 225, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ نٓ ۚ وَٱلْقَلَمِ وَمَا يَسْطُرُونَ', NULL, 29, 226, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 2, 'مَآ أَنتَ بِنِعْمَةِ رَبِّكَ بِمَجْنُونٍۢ', NULL, 29, 226, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 3, 'وَإِنَّ لَكَ لَأَجْرًا غَيْرَ مَمْنُونٍۢ', NULL, 29, 226, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 4, 'وَإِنَّكَ لَعَلَىٰ خُلُقٍ عَظِيمٍۢ', NULL, 29, 226, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 5, 'فَسَتُبْصِرُ وَيُبْصِرُونَ', NULL, 29, 226, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 6, 'بِأَييِّكُمُ ٱلْمَفْتُونُ', NULL, 29, 226, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 7, 'إِنَّ رَبَّكَ هُوَ أَعْلَمُ بِمَن ضَلَّ عَن سَبِيلِهِۦ وَهُوَ أَعْلَمُ بِٱلْمُهْتَدِينَ', NULL, 29, 226, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 8, 'فَلَا تُطِعِ ٱلْمُكَذِّبِينَ', NULL, 29, 226, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 9, 'وَدُّوا۟ لَوْ تُدْهِنُ فَيُدْهِنُونَ', NULL, 29, 226, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 10, 'وَلَا تُطِعْ كُلَّ حَلَّافٍۢ مَّهِينٍ', NULL, 29, 226, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 11, 'هَمَّازٍۢ مَّشَّآءٍۭ بِنَمِيمٍۢ', NULL, 29, 226, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 12, 'مَّنَّاعٍۢ لِّلْخَيْرِ مُعْتَدٍ أَثِيمٍ', NULL, 29, 226, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 13, 'عُتُلٍّۭ بَعْدَ ذَٰلِكَ زَنِيمٍ', NULL, 29, 226, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 14, 'أَن كَانَ ذَا مَالٍۢ وَبَنِينَ', NULL, 29, 226, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 15, 'إِذَا تُتْلَىٰ عَلَيْهِ ءَايَٰتُنَا قَالَ أَسَٰطِيرُ ٱلْأَوَّلِينَ', NULL, 29, 226, 7, 564, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 16, 'سَنَسِمُهُۥ عَلَى ٱلْخُرْطُومِ', NULL, 29, 226, 7, 565, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 17, 'إِنَّا بَلَوْنَٰهُمْ كَمَا بَلَوْنَآ أَصْحَٰبَ ٱلْجَنَّةِ إِذْ أَقْسَمُوا۟ لَيَصْرِمُنَّهَا مُصْبِحِينَ', NULL, 29, 226, 7, 565, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 18, 'وَلَا يَسْتَثْنُونَ', NULL, 29, 226, 7, 565, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 19, 'فَطَافَ عَلَيْهَا طَآئِفٌۭ مِّن رَّبِّكَ وَهُمْ نَآئِمُونَ', NULL, 29, 226, 7, 565, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 20, 'فَأَصْبَحَتْ كَٱلصَّرِيمِ', NULL, 29, 226, 7, 565, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 21, 'فَتَنَادَوْا۟ مُصْبِحِينَ', NULL, 29, 226, 7, 565, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 22, 'أَنِ ٱغْدُوا۟ عَلَىٰ حَرْثِكُمْ إِن كُنتُمْ صَٰرِمِينَ', NULL, 29, 226, 7, 565, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 23, 'فَٱنطَلَقُوا۟ وَهُمْ يَتَخَٰفَتُونَ', NULL, 29, 226, 7, 565, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 24, 'أَن لَّا يَدْخُلَنَّهَا ٱلْيَوْمَ عَلَيْكُم مِّسْكِينٌۭ', NULL, 29, 226, 7, 565, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 68), 25, 'وَغَدَوْا۟ عَلَىٰ حَرْدٍۢ قَٰدِرِينَ', NULL, 29, 226, 7, 565, false, NOW(), NOW()),
