((SELECT id FROM mst_surah WHERE surah_number = 72), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ قُلْ أُوحِىَ إِلَىَّ أَنَّهُ ٱسْتَمَعَ نَفَرٌۭ مِّنَ ٱلْجِنِّ فَقَالُوٓا۟ إِنَّا سَمِعْنَا قُرْءَانًا عَجَبًۭا', NULL, 29, 229, 7, 572, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 2, 'يَهْدِىٓ إِلَى ٱلرُّشْدِ فَـَٔامَنَّا بِهِۦ ۖ وَلَن نُّشْرِكَ بِرَبِّنَآ أَحَدًۭا', NULL, 29, 229, 7, 572, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 3, 'وَأَنَّهُۥ تَعَٰلَىٰ جَدُّ رَبِّنَا مَا ٱتَّخَذَ صَٰحِبَةًۭ وَلَا وَلَدًۭا', NULL, 29, 229, 7, 572, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 4, 'وَأَنَّهُۥ كَانَ يَقُولُ سَفِيهُنَا عَلَى ٱللَّهِ شَطَطًۭا', NULL, 29, 229, 7, 572, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 5, 'وَأَنَّا ظَنَنَّآ أَن لَّن تَقُولَ ٱلْإِنسُ وَٱلْجِنُّ عَلَى ٱللَّهِ كَذِبًۭا', NULL, 29, 229, 7, 572, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 6, 'وَأَنَّهُۥ كَانَ رِجَالٌۭ مِّنَ ٱلْإِنسِ يَعُوذُونَ بِرِجَالٍۢ مِّنَ ٱلْجِنِّ فَزَادُوهُمْ رَهَقًۭا', NULL, 29, 229, 7, 572, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 7, 'وَأَنَّهُمْ ظَنُّوا۟ كَمَا ظَنَنتُمْ أَن لَّن يَبْعَثَ ٱللَّهُ أَحَدًۭا', NULL, 29, 229, 7, 572, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 8, 'وَأَنَّا لَمَسْنَا ٱلسَّمَآءَ فَوَجَدْنَٰهَا مُلِئَتْ حَرَسًۭا شَدِيدًۭا وَشُهُبًۭا', NULL, 29, 229, 7, 572, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 9, 'وَأَنَّا كُنَّا نَقْعُدُ مِنْهَا مَقَٰعِدَ لِلسَّمْعِ ۖ فَمَن يَسْتَمِعِ ٱلْءَانَ يَجِدْ لَهُۥ شِهَابًۭا رَّصَدًۭا', NULL, 29, 229, 7, 572, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 10, 'وَأَنَّا لَا نَدْرِىٓ أَشَرٌّ أُرِيدَ بِمَن فِى ٱلْأَرْضِ أَمْ أَرَادَ بِهِمْ رَبُّهُمْ رَشَدًۭا', NULL, 29, 229, 7, 572, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 11, 'وَأَنَّا مِنَّا ٱلصَّٰلِحُونَ وَمِنَّا دُونَ ذَٰلِكَ ۖ كُنَّا طَرَآئِقَ قِدَدًۭا', NULL, 29, 229, 7, 572, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 12, 'وَأَنَّا ظَنَنَّآ أَن لَّن نُّعْجِزَ ٱللَّهَ فِى ٱلْأَرْضِ وَلَن نُّعْجِزَهُۥ هَرَبًۭا', NULL, 29, 229, 7, 572, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 13, 'وَأَنَّا لَمَّا سَمِعْنَا ٱلْهُدَىٰٓ ءَامَنَّا بِهِۦ ۖ فَمَن يُؤْمِنۢ بِرَبِّهِۦ فَلَا يَخَافُ بَخْسًۭا وَلَا رَهَقًۭا', NULL, 29, 229, 7, 572, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 14, 'وَأَنَّا مِنَّا ٱلْمُسْلِمُونَ وَمِنَّا ٱلْقَٰسِطُونَ ۖ فَمَنْ أَسْلَمَ فَأُو۟لَٰٓئِكَ تَحَرَّوْا۟ رَشَدًۭا', NULL, 29, 229, 7, 573, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 15, 'وَأَمَّا ٱلْقَٰسِطُونَ فَكَانُوا۟ لِجَهَنَّمَ حَطَبًۭا', NULL, 29, 229, 7, 573, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 16, 'وَأَلَّوِ ٱسْتَقَٰمُوا۟ عَلَى ٱلطَّرِيقَةِ لَأَسْقَيْنَٰهُم مَّآءً غَدَقًۭا', NULL, 29, 229, 7, 573, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 17, 'لِّنَفْتِنَهُمْ فِيهِ ۚ وَمَن يُعْرِضْ عَن ذِكْرِ رَبِّهِۦ يَسْلُكْهُ عَذَابًۭا صَعَدًۭا', NULL, 29, 229, 7, 573, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 18, 'وَأَنَّ ٱلْمَسَٰجِدَ لِلَّهِ فَلَا تَدْعُوا۟ مَعَ ٱللَّهِ أَحَدًۭا', NULL, 29, 229, 7, 573, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 19, 'وَأَنَّهُۥ لَمَّا قَامَ عَبْدُ ٱللَّهِ يَدْعُوهُ كَادُوا۟ يَكُونُونَ عَلَيْهِ لِبَدًۭا', NULL, 29, 229, 7, 573, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 20, 'قُلْ إِنَّمَآ أَدْعُوا۟ رَبِّى وَلَآ أُشْرِكُ بِهِۦٓ أَحَدًۭا', NULL, 29, 229, 7, 573, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 21, 'قُلْ إِنِّى لَآ أَمْلِكُ لَكُمْ ضَرًّۭا وَلَا رَشَدًۭا', NULL, 29, 229, 7, 573, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 22, 'قُلْ إِنِّى لَن يُجِيرَنِى مِنَ ٱللَّهِ أَحَدٌۭ وَلَنْ أَجِدَ مِن دُونِهِۦ مُلْتَحَدًا', NULL, 29, 229, 7, 573, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 23, 'إِلَّا بَلَٰغًۭا مِّنَ ٱللَّهِ وَرِسَٰلَٰتِهِۦ ۚ وَمَن يَعْصِ ٱللَّهَ وَرَسُولَهُۥ فَإِنَّ لَهُۥ نَارَ جَهَنَّمَ خَٰلِدِينَ فِيهَآ أَبَدًا', NULL, 29, 229, 7, 573, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 24, 'حَتَّىٰٓ إِذَا رَأَوْا۟ مَا يُوعَدُونَ فَسَيَعْلَمُونَ مَنْ أَضْعَفُ نَاصِرًۭا وَأَقَلُّ عَدَدًۭا', NULL, 29, 229, 7, 573, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 25, 'قُلْ إِنْ أَدْرِىٓ أَقَرِيبٌۭ مَّا تُوعَدُونَ أَمْ يَجْعَلُ لَهُۥ رَبِّىٓ أَمَدًا', NULL, 29, 229, 7, 573, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 26, 'عَٰلِمُ ٱلْغَيْبِ فَلَا يُظْهِرُ عَلَىٰ غَيْبِهِۦٓ أَحَدًا', NULL, 29, 229, 7, 573, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 27, 'إِلَّا مَنِ ٱرْتَضَىٰ مِن رَّسُولٍۢ فَإِنَّهُۥ يَسْلُكُ مِنۢ بَيْنِ يَدَيْهِ وَمِنْ خَلْفِهِۦ رَصَدًۭا', NULL, 29, 229, 7, 573, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 72), 28, 'لِّيَعْلَمَ أَن قَدْ أَبْلَغُوا۟ رِسَٰلَٰتِ رَبِّهِمْ وَأَحَاطَ بِمَا لَدَيْهِمْ وَأَحْصَىٰ كُلَّ شَىْءٍ عَدَدًۢا', NULL, 29, 229, 7, 573, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ يَٰٓأَيُّهَا ٱلْمُزَّمِّلُ', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 2, 'قُمِ ٱلَّيْلَ إِلَّا قَلِيلًۭا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 3, 'نِّصْفَهُۥٓ أَوِ ٱنقُصْ مِنْهُ قَلِيلًا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 4, 'أَوْ زِدْ عَلَيْهِ وَرَتِّلِ ٱلْقُرْءَانَ تَرْتِيلًا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 5, 'إِنَّا سَنُلْقِى عَلَيْكَ قَوْلًۭا ثَقِيلًا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 6, 'إِنَّ نَاشِئَةَ ٱلَّيْلِ هِىَ أَشَدُّ وَطْـًۭٔا وَأَقْوَمُ قِيلًا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 7, 'إِنَّ لَكَ فِى ٱلنَّهَارِ سَبْحًۭا طَوِيلًۭا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 8, 'وَٱذْكُرِ ٱسْمَ رَبِّكَ وَتَبَتَّلْ إِلَيْهِ تَبْتِيلًۭا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 9, 'رَّبُّ ٱلْمَشْرِقِ وَٱلْمَغْرِبِ لَآ إِلَٰهَ إِلَّا هُوَ فَٱتَّخِذْهُ وَكِيلًۭا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 10, 'وَٱصْبِرْ عَلَىٰ مَا يَقُولُونَ وَٱهْجُرْهُمْ هَجْرًۭا جَمِيلًۭا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 11, 'وَذَرْنِى وَٱلْمُكَذِّبِينَ أُو۟لِى ٱلنَّعْمَةِ وَمَهِّلْهُمْ قَلِيلًا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 12, 'إِنَّ لَدَيْنَآ أَنكَالًۭا وَجَحِيمًۭا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 13, 'وَطَعَامًۭا ذَا غُصَّةٍۢ وَعَذَابًا أَلِيمًۭا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 14, 'يَوْمَ تَرْجُفُ ٱلْأَرْضُ وَٱلْجِبَالُ وَكَانَتِ ٱلْجِبَالُ كَثِيبًۭا مَّهِيلًا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 15, 'إِنَّآ أَرْسَلْنَآ إِلَيْكُمْ رَسُولًۭا شَٰهِدًا عَلَيْكُمْ كَمَآ أَرْسَلْنَآ إِلَىٰ فِرْعَوْنَ رَسُولًۭا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 16, 'فَعَصَىٰ فِرْعَوْنُ ٱلرَّسُولَ فَأَخَذْنَٰهُ أَخْذًۭا وَبِيلًۭا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 17, 'فَكَيْفَ تَتَّقُونَ إِن كَفَرْتُمْ يَوْمًۭا يَجْعَلُ ٱلْوِلْدَٰنَ شِيبًا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 18, 'ٱلسَّمَآءُ مُنفَطِرٌۢ بِهِۦ ۚ كَانَ وَعْدُهُۥ مَفْعُولًا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 19, 'إِنَّ هَٰذِهِۦ تَذْكِرَةٌۭ ۖ فَمَن شَآءَ ٱتَّخَذَ إِلَىٰ رَبِّهِۦ سَبِيلًا', NULL, 29, 229, 7, 574, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 73), 20, '۞ إِنَّ رَبَّكَ يَعْلَمُ أَنَّكَ تَقُومُ أَدْنَىٰ مِن ثُلُثَىِ ٱلَّيْلِ وَنِصْفَهُۥ وَثُلُثَهُۥ وَطَآئِفَةٌۭ مِّنَ ٱلَّذِينَ مَعَكَ ۚ وَٱللَّهُ يُقَدِّرُ ٱلَّيْلَ وَٱلنَّهَارَ ۚ عَلِمَ أَن لَّن تُحْصُوهُ فَتَابَ عَلَيْكُمْ ۖ فَٱقْرَءُوا۟ مَا تَيَسَّرَ مِنَ ٱلْقُرْءَانِ ۚ عَلِمَ أَن سَيَكُونُ مِنكُم مَّرْضَىٰ ۙ وَءَاخَرُونَ يَضْرِبُونَ فِى ٱلْأَرْضِ يَبْتَغُونَ مِن فَضْلِ ٱللَّهِ ۙ وَءَاخَرُونَ يُقَٰتِلُونَ فِى سَبِيلِ ٱللَّهِ ۖ فَٱقْرَءُوا۟ مَا تَيَسَّرَ مِنْهُ ۚ وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ وَأَقْرِضُوا۟ ٱللَّهَ قَرْضًا حَسَنًۭا ۚ وَمَا تُقَدِّمُوا۟ لِأَنفُسِكُم مِّنْ خَيْرٍۢ تَجِدُوهُ عِندَ ٱللَّهِ هُوَ خَيْرًۭا وَأَعْظَمَ أَجْرًۭا ۚ وَٱسْتَغْفِرُوا۟ ٱللَّهَ ۖ إِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌۢ', NULL, 29, 230, 7, 575, false, NOW(), NOW()),
