((SELECT id FROM mst_surah WHERE surah_number = 74), 4, 'وَثِيَابَكَ فَطَهِّرْ', NULL, 29, 230, 7, 575, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 74), 5, 'وَٱلرُّجْزَ فَٱهْجُرْ', NULL, 29, 230, 7, 575, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 74), 6, 'وَلَا تَمْنُن تَسْتَكْثِرُ', NULL, 29, 230, 7, 575, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 74), 7, 'وَلِرَبِّكَ فَٱصْبِرْ', NULL, 29, 230, 7, 575, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 74), 8, 'فَإِذَا نُقِرَ فِى ٱلنَّاقُورِ', NULL, 29, 230, 7, 575, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 74), 9, 'فَذَٰلِكَ يَوْمَئِذٍۢ يَوْمٌ عَسِيرٌ', NULL, 29, 230, 7, 575, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 74), 10, 'عَلَى ٱلْكَٰفِرِينَ غَيْرُ يَسِيرٍۢ', NULL, 29, 230, 7, 575, false, NOW(), NOW()),
