((SELECT id FROM mst_surah WHERE surah_number = 74), 13, 'وَبَنِينَ شُهُودًۭا', NULL, 29, 230, 7, 575, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 74), 14, 'وَمَهَّدتُّ لَهُۥ تَمْهِيدًۭا', NULL, 29, 230, 7, 575, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 74), 15, 'ثُمَّ يَطْمَعُ أَنْ أَزِيدَ', NULL, 29, 230, 7, 575, false, NOW(), NOW()),
